INSERT INTO `wp_aioseo_cache` VALUES (4,'addons','[{\"sku\":\"aioseo-redirects\",\"name\":\"Redirection Manager\",\"version\":\"1.4.15\",\"image\":null,\"icon\":\"\",\"levels\":[\"business\",\"agency\",\"pro\",\"elite\"],\"currentLevels\":[\"pro\",\"elite\"],\"requiresUpgrade\":true,\"description\":\"<p>Our Redirection Manager allows you to create and manage redirects for 404s or modified posts.<\\/p>\\n\",\"descriptionVersion\":0,\"downloadUrl\":\"\",\"productUrl\":\"https:\\/\\/aioseo.com\\/features\\/redirection-manager\\/\",\"learnMoreUrl\":\"https:\\/\\/aioseo.com\\/features\\/redirection-manager\\/\",\"manageUrl\":\"https:\\/\\/route#aioseo-redirects:redirects\",\"features\":[{\"license_level\":\"elite\",\"feature\":\"404-parent-redirect\"}]},{\"sku\":\"aioseo-link-assistant\",\"name\":\"Link Assistant\",\"version\":\"1.1.13\",\"image\":null,\"icon\":\"\",\"levels\":[\"agency\",\"pro\",\"elite\"],\"currentLevels\":[\"pro\",\"elite\"],\"requiresUpgrade\":true,\"description\":\"<p>Super-charge your SEO with Link Assistant! Get relevant suggestions for adding internal links to older content as well as finding any orphaned posts that have no internal links. Use our reporting feature to see all link suggestions or add them directly from any page or post.<\\/p>\\n\",\"descriptionVersion\":0,\"downloadUrl\":\"\",\"productUrl\":\"https:\\/\\/aioseo.com\\/docs\\/link-assistant\\/\",\"learnMoreUrl\":\"https:\\/\\/aioseo.com\\/docs\\/link-assistant\\/\",\"manageUrl\":\"https:\\/\\/route#aioseo-link-assistant:overview\",\"features\":[]},{\"sku\":\"aioseo-video-sitemap\",\"name\":\"Video Sitemap\",\"version\":\"1.1.26\",\"image\":null,\"icon\":\"\",\"levels\":[\"individual\",\"business\",\"agency\",\"pro\",\"elite\"],\"currentLevels\":[\"pro\",\"elite\"],\"requiresUpgrade\":true,\"description\":\"<p>The Video Sitemap works in much the same way as the XML Sitemap module, it generates an XML Sitemap specifically for video content on your site. Search engines use this information to display rich snippet information in search results.<\\/p>\\n\",\"descriptionVersion\":0,\"downloadUrl\":\"\",\"productUrl\":\"https:\\/\\/aioseo.com\\/docs\\/how-to-create-a-video-sitemap\\/\",\"learnMoreUrl\":\"https:\\/\\/aioseo.com\\/docs\\/how-to-create-a-video-sitemap\\/\",\"manageUrl\":\"https:\\/\\/route#aioseo-sitemaps:video-sitemap\",\"features\":[]},{\"sku\":\"aioseo-local-business\",\"name\":\"Local Business SEO\",\"version\":\"1.3.12\",\"image\":null,\"icon\":\"svg-local-business\",\"levels\":[\"business\",\"agency\",\"plus\",\"pro\",\"elite\"],\"currentLevels\":[\"plus\",\"pro\",\"elite\"],\"requiresUpgrade\":true,\"description\":\"<p>Local Business schema markup enables you to tell Google about your business, including your business name, address and phone number, opening hours and price range. This information may be displayed as a Knowledge Graph card or business carousel.<\\/p>\\n\",\"descriptionVersion\":0,\"downloadUrl\":\"\",\"productUrl\":\"https:\\/\\/aioseo.com\\/docs\\/local-business-seo\\/\",\"learnMoreUrl\":\"https:\\/\\/aioseo.com\\/docs\\/local-business-seo\\/\",\"manageUrl\":\"https:\\/\\/route#aioseo-local-seo:locations\",\"features\":[]},{\"sku\":\"aioseo-news-sitemap\",\"name\":\"News Sitemap\",\"version\":\"1.0.21\",\"image\":null,\"icon\":\"svg-sitemaps-pro\",\"levels\":[\"business\",\"agency\",\"pro\",\"elite\"],\"currentLevels\":[\"pro\",\"elite\"],\"requiresUpgrade\":true,\"description\":\"<p>Our Google News Sitemap lets you control which content you submit to Google News and only contains articles that were published in the last 48 hours. In order to submit a News Sitemap to Google, you must have added your site to Google\\u2019s Publisher Center and had it approved.<\\/p>\\n\",\"descriptionVersion\":0,\"downloadUrl\":\"\",\"productUrl\":\"https:\\/\\/aioseo.com\\/docs\\/how-to-create-a-google-news-sitemap\\/\",\"learnMoreUrl\":\"https:\\/\\/aioseo.com\\/docs\\/how-to-create-a-google-news-sitemap\\/\",\"manageUrl\":\"https:\\/\\/route#aioseo-sitemaps:news-sitemap\",\"features\":[]},{\"sku\":\"aioseo-index-now\",\"name\":\"IndexNow\",\"version\":\"1.0.13\",\"image\":null,\"icon\":\"\",\"levels\":[\"business\",\"agency\",\"basic\",\"plus\",\"pro\",\"elite\"],\"currentLevels\":[\"basic\",\"plus\",\"pro\",\"elite\"],\"requiresUpgrade\":true,\"description\":\"<p>Add IndexNow support to instantly notify search engines when your content has changed. This helps the search engines to prioritize the changes on your website and helps you rank faster.<\\/p>\\n\",\"descriptionVersion\":0,\"downloadUrl\":\"\",\"productUrl\":\"https:\\/\\/aioseo.com\\/index-now\",\"learnMoreUrl\":\"https:\\/\\/aioseo.com\\/index-now\",\"manageUrl\":\"https:\\/\\/route#aioseo-settings:webmaster-tools\",\"features\":[]},{\"sku\":\"aioseo-rest-api\",\"name\":\"REST API\",\"version\":\"1.0.9\",\"image\":null,\"icon\":\"PHN2ZyB4bWxucz0iaHR0cDovL3d3dy53My5vcmcvMjAwMC9zdmciIHZpZXdCb3g9IjAgMCAyNCAyNCIgY2xhc3M9ImFpb3Nlby1jb2RlIj48cGF0aCBkPSJNOS40IDE2LjZMNC44IDEybDQuNi00LjZMOCA2bC02IDYgNiA2IDEuNC0xLjR6bTUuMiAwbDQuNi00LjYtNC42LTQuNkwxNiA2bDYgNi02IDYtMS40LTEuNHoiIGZpbGw9ImN1cnJlbnRDb2xvciIvPjwvc3ZnPg==\",\"levels\":[\"plus\",\"pro\",\"elite\"],\"currentLevels\":[\"plus\",\"pro\",\"elite\"],\"requiresUpgrade\":true,\"description\":\"<p>Manage your post and term SEO meta via the WordPress REST API. This addon also works seamlessly with headless WordPress installs.<\\/p>\\n\",\"descriptionVersion\":0,\"downloadUrl\":\"\",\"productUrl\":\"https:\\/\\/aioseo.com\\/feature\\/rest-api\\/\",\"learnMoreUrl\":\"https:\\/\\/aioseo.com\\/feature\\/rest-api\\/\",\"manageUrl\":\"\",\"features\":[]},{\"sku\":\"aioseo-image-seo\",\"name\":\"Image SEO\",\"version\":\"1.2.4\",\"image\":null,\"icon\":\"\",\"levels\":[\"business\",\"agency\",\"plus\",\"pro\",\"elite\"],\"currentLevels\":[\"plus\",\"pro\",\"elite\"],\"requiresUpgrade\":true,\"description\":\"<p>Globally control the Title, Alt Text, Caption and Descriptions for images in your content. These attributes are essential for both accessibility and SEO.<\\/p>\\n\",\"descriptionVersion\":0,\"downloadUrl\":\"\",\"productUrl\":\"https:\\/\\/aioseo.com\\/docs\\/using-the-image-seo-features-in-all-in-one-seo\\/\",\"learnMoreUrl\":\"https:\\/\\/aioseo.com\\/docs\\/using-the-image-seo-features-in-all-in-one-seo\\/\",\"manageUrl\":\"https:\\/\\/route#aioseo-search-appearance:media\",\"features\":[]},{\"sku\":\"aioseo-eeat\",\"name\":\"Author SEO (E-E-A-T)\",\"version\":\"1.2.10\",\"image\":null,\"icon\":\"\",\"levels\":[\"plus\",\"pro\",\"elite\"],\"currentLevels\":[\"plus\",\"pro\",\"elite\"],\"requiresUpgrade\":true,\"description\":\"<p>Optimize your site for Google\'s E-E-A-T ranking factor by proving your writer\'s expertise through author schema markup and new UI elements.<\\/p>\\n\",\"descriptionVersion\":0,\"downloadUrl\":\"\",\"productUrl\":\"https:\\/\\/aioseo.com\\/features\\/eeat\\/\",\"learnMoreUrl\":\"https:\\/\\/aioseo.com\\/features\\/eeat\\/\",\"manageUrl\":\"https:\\/\\/route#aioseo-search-appearance:author-seo\",\"features\":[]}]',0,'2026-04-22 11:19:21','2026-04-16 13:50:02','2026-04-21 11:19:21'),(5,'db_schema','{\"wp_actionscheduler_actions\":[\"action_id\",\"args\",\"attempts\",\"claim_id\",\"extended_args\",\"group_id\",\"hook\",\"last_attempt_gmt\",\"last_attempt_local\",\"priority\",\"schedule\",\"scheduled_date_gmt\",\"scheduled_date_local\",\"status\"],\"wp_actionscheduler_claims\":[\"claim_id\",\"date_created_gmt\"],\"wp_actionscheduler_groups\":[\"group_id\",\"slug\"],\"wp_actionscheduler_logs\":[\"action_id\",\"log_date_gmt\",\"log_date_local\",\"log_id\",\"message\"],\"wp_aioseo_ai_insights_keyword_reports\":[\"brands\",\"brands_mentioned\",\"created\",\"id\",\"keyword\",\"results\",\"status\",\"updated\",\"uuid\"],\"wp_aioseo_blc_cache\":[\"created\",\"expiration\",\"id\",\"is_object\",\"key\",\"updated\",\"value\"],\"wp_aioseo_blc_link_status\":[\"broken\",\"created\",\"dismissed\",\"final_url\",\"first_failure\",\"http_st