INSERT INTO `wp_aioseo_notifications` VALUES (1,'69e0e9054809d',NULL,'Розширена підтримка WooCommerce','Ми виявили, що ви використовуєте WooCommerce. Оновіться до AIOSEO Pro, щоб розблокувати наші розширені функції SEO для електронної комерції, включаючи SEO для категорій товарів та багато іншого.','info','[\"all\"]',NULL,'woo-upsell','2026-04-16 13:49:57',NULL,'Оновіть до версії Pro','https://aioseo.com/lite-upgrade/?utm_source=WordPress&utm_campaign=liteplugin&utm_medium=woo-notification-upsell',NULL,NULL,0,0,'2026-04-16 13:49:57','2026-04-16 13:49:57'),(2,'69e0e908255cf',NULL,'Have you connected your site to Google Search Console?','AIOSEO can now verify whether your site is correctly verified with Google Search Console and that your sitemaps have been submitted correctly. Connect with Google Search Console now to ensure your content is being added to Google as soon as possible for increased rankings.','warning','[\"all\"]',NULL,'search-console-site-not-connected','2026-04-16 13:50:00',NULL,'Connect to Google Search Console','https://route#aioseo-settings&aioseo-scroll=google-search-console-settings&aioseo-highlight=google-search-console-settings:webmaster-tools?activetool=googleSearchConsole',NULL,NULL,0,0,'2026-04-16 13:50:00','2026-04-16 13:50:00'),(3,'69e0e99e6cb4d',NULL,'Заблоковані пошукові системи','Попередження: AIOSEO виявив, що ви блокуєте доступ до пошукових систем. Ви можете змінити це в Налаштування > Читання, якщо це було ненавмисно.','error','[\"all\"]',NULL,'blog-visibility','2026-04-16 13:52:30',NULL,'Полагодити зараз','http://localhost:8080/wp-admin/options-reading.php','Нагадайте мені пізніше','http://action#notification/blog-visibility-reminder',0,0,'2026-04-16 13:52:30','2026-04-16 13:52:30');
/*!40000 ALTER TABLE `wp_aioseo_notifications` ENABLE KEYS */;
UNLOCK TABLES;

