/\";s:6:\"avatar\";s:120:\"https://secure.gravatar.com/avatar/fa4a4b2688afb8d238bb035f31fda4d07dabd67ccf41576276e5eb084463d617?s=96&d=monsterid&r=g\";s:12:\"display_name\";s:12:\"tarunvijwani\";}s:12:\"pauloarromba\";a:3:{s:7:\"profile\";s:44:\"https://profiles.wordpress.org/pauloarromba/\";s:6:\"avatar\";s:120:\"https://secure.gravatar.com/avatar/ab6034aa12c0e53f21978df9e470f161f06810d814082cbe3ab74450f0618818?s=96&d=monsterid&r=g\";s:12:\"display_name\";s:13:\"Paulo Arromba\";}s:9:\"saadtarhi\";a:3:{s:7:\"profile\";s:41:\"https://profiles.wordpress.org/saadtarhi/\";s:6:\"avatar\";s:120:\"https://secure.gravatar.com/avatar/f4fd0df69b8c7bf3a3e6526df3b42c3854de544904ef825bfd549afc9829f645?s=96&d=monsterid&r=g\";s:12:\"display_name\";s:7:\"Saad T.\";}s:4:\"bor0\";a:3:{s:7:\"profile\";s:36:\"https://profiles.wordpress.org/bor0/\";s:6:\"avatar\";s:120:\"https://secure.gravatar.com/avatar/787d8ea71701ced680cd80411d656c20e0e600be5d34f6ce3478143d43dc9fd9?s=96&d=monsterid&r=g\";s:12:\"display_name\";s:16:\"Boro Sitnikovski\";}s:5:\"kloon\";a:3:{s:7:\"profile\";s:37:\"https://profiles.wordpress.org/kloon/\";s:6:\"avatar\";s:120:\"https://secure.gravatar.com/avatar/c7c708f5b0957714ab48e00220b0f74acccb43b70fa0d4b5ee091d59951ae751?s=96&d=monsterid&r=g\";s:12:\"display_name\";s:17:\"Gerhard Potgieter\";}s:12:\"coreymckrill\";a:3:{s:7:\"profile\";s:44:\"https://profiles.wordpress.org/coreymckrill/\";s:6:\"avatar\";s:120:\"https://secure.gravatar.com/avatar/9cc64cf0f650f165ac55f1294105259f82f2b72c4c24903a79af6d6cd1ad2a9a?s=96&d=monsterid&r=g\";s:12:\"display_name\";s:13:\"Corey McKrill\";}s:12:\"jorgeatorres\";a:3:{s:7:\"profile\";s:44:\"https://profiles.wordpress.org/jorgeatorres/\";s:6:\"avatar\";s:120:\"https://secure.gravatar.com/avatar/33d6a063c7411775135383c5bae6cd4e45d094b72ec062c96ceafca5e2a4956f?s=96&d=monsterid&r=g\";s:12:\"display_name\";s:15:\"Jorge A. Torres\";}s:10:\"leifsinger\";a:3:{s:7:\"profile\";s:42:\"https://profiles.wordpress.org/leifsinger/\";s:6:\"avatar\";s:120:\"https://secure.gravatar.com/avatar/8107603a6bbc5ff73e07e2450f260335af41a5adb2cccd80cba20cdd28b96651?s=96&d=monsterid&r=g\";s:12:\"display_name\";s:11:\"Leif Singer\";}s:9:\"neosinner\";a:3:{s:7:\"profile\";s:41:\"https://profiles.wordpress.org/neosinner/\";s:6:\"avatar\";s:120:\"https://secure.gravatar.com/avatar/68b52d53a3c6dd39841f697853a1965057c6f3aeb9e89f7d960d1921ffa90d29?s=96&d=monsterid&r=g\";s:12:\"display_name\";s:13:\"Ján Mikláš\";}}s:8:\"requires\";s:3:\"6.8\";s:6:\"tested\";s:5:\"6.9.4\";s:12:\"requires_php\";s:3:\"7.4\";s:16:\"requires_plugins\";a:0:{}s:6:\"rating\";i:90;s:7:\"ratings\";a:5:{i:5;i:3948;i:4;i:195;i:3;i:107;i:2;i:107;i:1;i:407;}s:11:\"num_ratings\";i:4764;s:11:\"support_url\";s:49:\"https://wordpress.org/support/plugin/woocommerce/\";s:15:\"support_threads\";i:292;s:24:\"support_threads_resolved\";i:176;s:15:\"active_installs\";i:7000000;s:12:\"last_updated\";s:22:\"2026-04-14 12:01pm GMT\";s:5:\"added\";s:10:\"2011-09-27\";s:8:\"homepage\";s:24:\"https://woocommerce.com/\";s:8:\"sections\";a:6:{s:11:\"description\";s:17429:\"<p><a href=\"https://woocommerce.com/woocommerce/\" rel=\"nofollow ugc\">WooCommerce</a> &#8211; це відкрита електронна комерція для WordPress.</p>\n<p>Наша гнучка та безкоштовна базова платформа працює за підтримки глобальної спільноти. Свобода, що надається відкритим вихідним кодом, означає, що ви зберігаєте повний контроль над вмістом та базою даних свого магазину.</p>\n<p>Незалежно від того, чи відкриваєте ви бізнес, займаєтеся роздрібною торгівлею в Інтернеті чи розробляєте сайти для клієнтів, використовуйте WooCommerce для магазину, який потужно поєднує контент і комерцію.</p>\n<ul>\n<li><strong>Створюйте стильні та оригінальні віртуальні вітрини</strong> за допомогою <a href=\"https://woocommerce.com/product-category/themes/?utm_medium=referral&amp;utm_source=wordpress.org&amp;utm_campaign=wp_org_repo_listing\" rel=\"nofollow ugc\">тем</a>, які підійдуть для вашого бренду чи галузі.</li>\n<li><strong>Збільште дохід</strong> за допомогою оптимізованого <a href=\"https://woocommerce.com/checkout-blocks/?utm_medium=referral&amp;utm_source=wordpress.org&amp;utm_campaign=wp_org_repo_listing\" rel=\"nofollow ugc\">кошика</a>, що спрощує покупку.</li>\n<li><strong>Налаштуйте сторінки товарів за лічені хвилини</strong> за допомогою модульних <a href=\"https://woocommerce.com/document/woocommerce-blocks/?utm_medium=referral&amp;utm_source=wordpress.org&amp;utm_campaign=wp_org_repo_listing\" rel=\"nofollow ugc\">блоків товарів</a>.</li>\n<li>Пропонуйте фізичні та цифрові товари та їх варіанти, конфігурації користувача, моментальні завантаження та пов&#8217;язані позиції.</li>\n<li>Продавайте <a href=\"https://woocommerce.com/products/woocommerce-subscriptions/?utm_medium=referral&amp;utm_source=wordpress.org&amp;utm_campaign=wp_org_repo_listing\" rel=\"nofollow ugc\">підписки</a>, <a href=\"https://woocommerce.com/products/woocommerce-bookings/?utm_medium=referral&amp;utm_source=wordpress.org&amp;utm_campaign=wp_org_repo_listing\" rel=\"nofollow ugc\">бронювання</a> або <a href=\"https://woocommerce.com/products/woocommerce-memberships/?utm_medium=referral&amp;utm_source=wordpress.org&amp;utm_campaign=wp_org_repo_listing\" rel=\"nofollow ugc\">членства</a> за допомогою наших розширень, перевірених розробниками.</li>\n<li><strong>Підніміться в ТОП пошукових результатів</strong>, ефективно використовуючи можливості <a href=\"https://www.searchenginejournal.com/wordpress-best-cms-seo/\" rel=\"nofollow ugc\">WordPress SEO</a>.</li>\n<li><strong>Побудовано на платформі, яка масштабується.</strong> Отримайте гнучку електронну комерцію для <a href=\"https://woocommerce.com/high-volume-stores/?utm_medium=referral&amp;utm_source=wordpress.org&amp;utm_campaign=wp_org_repo_listing\" rel=\"nofollow ugc\">великих інтернет-магазинів</a>.</li>\n</ul>\n<h4>ВСІ ІНСТРУМЕНТИ, ЯКІ ВАМ ПОТРІБНІ ДЛЯ ПРОДАЖУ</h4>\n<p>Вбудовані інструменти та інтеграція з популярними ресурсами допоможуть вам ефективно керувати бізнес-операціями. Багато послуг можна безкоштовно додати одним натисканням миші за допомогою додаткового <a href=\"https://woocommerce.com/document/woocommerce-setup-wizard/?utm_medium=referral&amp;utm_source=wordpress.org&amp;utm_campaign=wp_org_repo_listing\" rel=\"nofollow ugc\">Майстра налаштування</a>.</p>\n<ul>\n<li><strong>Оберіть, як ви хочете отримувати платежі</strong>. Зручно керуйте платежами з комфортом вашого магазину за допомогою <a href=\"https://woocommerce.com/payments/?utm_medium=referral&amp;utm_source=wordpress.org&amp;utm_campaign=wp_org_repo_listing\" rel=\"nofollow ugc\">WooPayments</a> (доступно в США, Великобританії, Ірландії, Австралії, Новій Зеландії, Канаді, Іспанії, Франції, Німеччині та Італії). Безпечно приймайте кредитні картки, мобільні гаманці, банківські перекази та готівку завдяки <a href=\"https://woocommerce.com/product-category/woocommerce-extensions/payment-gateways/?utm_medium=referral&amp;utm_source=wordpress.org&amp;utm_campaign=wp_org_repo_listing\" rel=\"nofollow ugc\">100+ платіжним шлюзам</a> – включаючи <a href=\"https://woocommerce.com/products/stripe/?utm_medium=referral&amp;utm_source=wordpress.org&amp;utm_campaign=wp_org_repo_listing\" rel=\"nofollow ugc\">Stripe</a>, <a href=\"https://woocommerce.com/products/woocommerce-gateway-paypal-checkout/?utm_medium=referral&amp;utm_source=wordpress.org&amp;utm_campaign=wp_org_repo_listing\" rel=\"nofollow ugc\">PayPal</a> та <a href=\"https://woocommerce.com/products/square/?utm_medium=referral&amp;utm_source=wordpress.org&amp;utm_campaign=wp_org_repo_listing\" rel=\"nofollow ugc\">Square</a>.</li>\n<li><strong>Налаштуйте свої параметри доставки</strong>. Друкуйте мітки USPS прямо з вашої Майстерні та навіть відкладайте забір вантажу за допомогою <a href=\"https://woocommerce.com/products/shipping/?utm_medium=referral&amp;utm_source=wordpress.org&amp;utm_campaign=wp_org_repo_listing\" rel=\"nofollow ugc\">WooCommerce Shipping</a> (тільки для США). Підключайтеся до <a href=\"https://woocommerce.com/product-category/woocommerce-extensions/shipping-methods/?utm_medium=referral&amp;utm_source=wordpress.org&amp;utm_campaign=wp_org_repo_listing\" rel=\"nofollow ugc\">відомих перевізників</a>, таких як UPS та FedEx &#8211; а також широкого спектру рішень щодо доставки, інвентаризації та виконання замовлень для вашого регіону.</li>\n<li><strong>Спрощення обліку податку з продажів.</strong> Додайте <a href=\"https://woocommerce.com/products/tax/?utm_medium=referral&amp;utm_source=wordpress.org&amp;utm_campaign=wp_org_repo_listing\" rel=\"nofollow ugc\">WooCommerce Tax</a> або <a href=\"https://woocommerce.com/product-category/woocommerce-extensions/tax?utm_medium=referral&amp;utm_source=wordpress.org&amp;utm_campaign=wp_org_repo_listing\" rel=\"nofollow ugc\">подібні інтегровані сервіси</a>, щоб автоматизувати розрахунки.</li>\n</ul>\n<h4>Розвивайте свій бізнес, додавайте функції та контролюйте свій магазин на ходу</h4>\n<p>WooCommerce means business. Keep tabs on the performance metrics most important to you with a powerful and flexible central dashboard built into WooCommerce.</p>\n<p>Розширюйте свою аудиторію через маркетингові та соціальні канали з інтеграціями <a href=\"https://woocommerce.com/products/google-ads/?utm_medium=referral&amp;utm_source=wordpress.org&amp;utm_campaign=wp_org_repo_listing\" rel=\"nofollow ugc\">Google Ads</a>, <a href=\"https://woocommerce.com/products/hubspot-for-woocommerce/?utm_medium=referral&amp;utm_source=wordpress.org&amp;utm_campaign=wp_org_repo_listing\" rel=\"nofollow ugc\">HubSpot</a>, <a href=\"https://woocommerce.com/products/mailchimp-for-woocommerce/?utm_medium=referral&amp;utm_source=wordpress.org&amp;utm_campaign=wp_org_repo_listing\" rel=\"nofollow ugc\">Mailchimp</a> та <a href=\"https://woocommerce.com/products/facebook/?utm_medium=referral&amp;utm_source=wordpress.org&amp;utm_campaign=wp_org_repo_listing\" rel=\"nofollow ugc\">Facebook</a>. Завжди можете переглянути перелік у Майстерні <a href=\"https://woocommerce.com/document/marketing-hub/?utm_medium=referral&amp;utm_source=wordpress.org&amp;utm_campaign=wp_org_repo_listing\" rel=\"nofollow ugc\">Маркетингової платформи</a> для нових ідей та порад, що допоможуть вам досягти успіху.</p>\n<p>Enhance store functionality with hundreds of free and paid extensions from the <a href=\"https://woocommerce.com/products/?utm_medium=referral&amp;utm_source=wordpress.org&amp;utm_campaign=wp_org_repo_listing\" rel=\"nofollow ugc\">WooCommerce Marketplace</a>. Our developers <a href=\"https://woocommerce.com/document/marketplace-overview/#section-6?utm_medium=referral&amp;utm_source=wordpress.org&amp;utm_campaign=wp_org_repo_listing\" rel=\"nofollow ugc\">vet each new extension</a> and regularly review existing extensions to maintain Marketplace quality standards. We are actively <a href=\"https://woocommerce.com/document/marketplace-overview/#section-2?utm_medium=referral&amp;utm_source=wordpress.org&amp;utm_campaign=wp_org_repo_listing\" rel=\"nofollow ugc\">looking for products that help store builders create successful stores</a>.</p>\n<p>Керуйте своїм магазином з будь-якого місця за допомогою безкоштовного <a href=\"https://woocommerce.com/mobile/?utm_medium=referral&amp;utm_source=wordpress.org&amp;utm_campaign=wp_org_repo_listing\" rel=\"nofollow ugc\">мобільного додатку</a> WooCommerce (для Android та iOS). У вас буде звукове попередження на вашому смартфоні кожен раз коли у вас в магазині здійснена покупка.</p>\n<h4>Завжди контролюйте та відстежуйте дані вашого магазину</h4>\n<p>За допомогою <a href=\"https://woocommerce.com/woocommerce/\" rel=\"nofollow ugc\">WooCommerce</a> ваші дані належать вам. Завжди.</p>\n<p>Даючи згоду поділитися з нами <a href=\"https://woocommerce.com/usage-tracking/?utm_medium=referral&amp;utm_source=wordpress.org&amp;utm_campaign=wp_org_repo_listing\" rel=\"nofollow ugc\">даними про використання</a>, ви можете бути впевнені що дані будуть зашифровані та захищені. Ви можете у будь-який час відкликати свою згоду. Це ніяк не вплине на роботу магазину.</p>\n<p>На відміну від готових рішень для електронної комерції, дані магазину WooCommerce мають гарантовану майбутню сумісність; ви вільні експортувати весь вміст і перенести свій сайт на будь-яку обрану вами платформу. Без обмежень.</p>\n<h4>Чому розробники вибирають (і люблять) WooCommerce</h4>\n<p>Розробники можуть використовувати <a href=\"https://woocommerce.com/woocommerce/\" rel=\"nofollow ugc\">WooCommerce</a> для створення, налаштування та масштабування магазину, щоб відповідати точним вимогам клієнта, роблячи покращення за допомогою розширень або власних рішень.</p>\n<ul>\n<li>Використовуйте <a href=\"https://woocommerce.com/document/introduction-to-hooks-actions-and-filters/?utm_medium=referral&amp;utm_source=wordpress.org&amp;utm_campaign=wp_org_repo_listing\" rel=\"nofollow ugc\">хуки (гачки) та фільтри</a> для створення та модифікації функцій.</li>\n<li>Інтегруйте практично будь-який сервіс, використовуючи надійний <a href=\"https://developer.woocommerce.com/docs/getting-started-with-the-woocommerce-rest-api/?utm_medium=referral&amp;utm_source=wordpress.org&amp;utm_campaign=wp_org_repo_listing\" rel=\"nofollow ugc\">REST API</a> та веб-хуки (веб-гачки).</li>\n<li>Проектуйте та створюйте власні блоки вмісту за допомогою React.</li>\n<li><a href=\"https://developer.woocommerce.com/docs/category/extension-development/?utm_medium=referral&amp;utm_source=wordpress.org&amp;utm_campaign=wp_org_repo_listing\" rel=\"nofollow ugc\">Перегляд та зміна</a> будь-якого аспекту основного коду плагіна.</li>\n<li>Прискорюйте процес розробки, використовуючи надшвидкий <a href=\"https://developer.woocommerce.com/docs/category/wc-cli/?utm_medium=referral&amp;utm_source=wordpress.org&amp;utm_campaign=wp_org_repo_listing\" rel=\"nofollow ugc\">CLI</a>.</li>\n</ul>\n<p>Основна платформа ретельно і часто перевіряється за підтримки спеціальної команди розробників, яка працює в різних часових поясах. Вичерпна документація оновлюється з кожним випуском, дозволяючи вам створювати необхідний магазин саме для ваших потреб.</p>\n<h4>Будьте частиною нашої зростаючої міжнародної спільноти</h4>\n<p>Активні, численні учасники швидкозростаючої спільноти WooCommerce допомагають досягти успіхів у комерції.</p>\n<p>По всьому світу організовуються <a href=\"https://woocommerce.com/meetups/?utm_medium=referral&amp;utm_source=wordpress.org&amp;utm_campaign=wp_org_repo_listing\" rel=\"nofollow ugc\">Зустрічі WooCommerce</a>, які ви можете відвідувати безкоштовно та брати участь у їх роботі. Ці події &#8211; чудовий спосіб повчитися у інших, поділитися своїм досвідом та встановити зв’язок із однодумцями.</p>\n<p>Також WooCommerce – постійний учасник WordCamp в різних регіонах. Ми будемо раді бачити і вас в наших рядах.</p>\n<h4>Зробіть свій внесок, робіть переклади</h4>\n<p>Розробку та підтримку WooCommerce здійснює компанія Automattic, розробник WordPress.com та Jetpack. Також з нами працюють сотні незалежних авторів і завжди є перспективи для зростання. Перейдіть в <a href=\"https://github.com/woocommerce/woocommerce?utm_medium=referral&amp;utm_source=wordpress.org&amp;utm_campaign=wp_org_repo_listing\" rel=\"nofollow ugc\">репозиторій WooCommerce GitHub</a>, щоб дізнатися, який внесок ви можете зробити.</p>\n<p>WooCommerce перекладено різними мовами, включаючи датську, українську та перську. Допоможіть локалізувати WooCommerce ще більше, додавши свою мову на <a href=\"https://translate.wordpress.org/projects/wp-plugins/woocommerce/?utm_medium=referral&amp;utm_source=wordpress.org&amp;utm_campaign=wp_org_repo_listing\" rel=\"nofollow ugc\">translate.wordpress.org</a>.</p>\n<h4>Підключення до WooCommerce.com</h4>\n<p>Ви можете підключити свій магазин до <a href=\"https://woocommerce.com/\" rel=\"nofollow ugc\">WooCommerce.com</a>, щоб керувати підписками на WooCommerce Marketplace і отримувати оновлення продуктів, не виходячи з адмінки WordPress. Підключення також дозволяє встановлювати придбані продукти прямо з WooCommerce.com і спрощує доступ до технічної підтримки. Якщо ви хочете дізнатися про те, які дані збираються і як вони використовуються, будь ласка, зверніться до нашої <a href=\"https://automattic.com/privacy/\" rel=\"nofollow ugc\">Політики конфіденційності</a>.</p>\n\";s:12:\"installation\";s:3805:\"<h4>Мінімальні вимоги</h4>\n<ul>\n<li>Потрібен PHP 7.4 або вище (рекомендується PHP 8.0 або вище)</li>\n<li>Потрібна версія MySQL 5.5.5 або вище, або MariaDB версії 10.1 або новішої</li>\n<li>WordPress 6.8 або вище</li>\n<li>(Recommended) WordPress <a href=\"https://woocommerce.com/document/increasing-the-wordpress-memory-limit/\" rel=\"nofollow ugc\">memory limit</a> of 256 MB or greater.</li>\n<li>(Recommended) <a href=\"https://woocommerce.com/document/ssl-and-https/\" rel=\"nofollow ugc\">HTTPS</a> support.</li>\n</ul>\n<h4>Автоматичне встановлення</h4>\n<p>Автоматичне встановлення це найлегший шлях, оскільки WordPress бере на себе передачу файлів і вам не треба залишати свій браузер. Щоб зробити автоматичне встановлення WooCommerce, увійдіть до своєї майстерні WordPress, перейдіть до меню &#8220;Плагіни&#8221; та натисніть &#8220;Додати новий&#8221;.</p>\n<p>У полі пошуку введіть &#8220;WooCommerce&#8221;, а потім натисніть кнопку &#8220;Пошук плагінів&#8221;. Відкриється детальна інформація про плагін, в тому числі номер версії, рейтинг і опис. Найголовніше, звичайно, ви можете встановити його! Натисніть &#8220;Встановити зараз&#8221;, а все інше зробить WordPress.</p>\n<h4>Ручне встановлення</h4>\n<p>Ручне встановлення передбачає завантаження нашого WooCommerce плагіну та відвантаження його на ваш вебсервер через ваш улюблений FTP додаток. Кодекс WordPress містить <a href=\"https://wordpress.org/support/article/managing-plugins/#manual-plugin-installation\" rel=\"ugc\">інструкції як це зробити тут</a>.</p>\n<h4>Оновлення</h4>\n<p>Автоматичні оновлення повинні працювати безперебійно, але ми все-таки радимо створити резервну копію вашого веб-сайту.</p>\n<p>Якщо у вас виникли проблеми зі сторінками магазину/категорії після оновлення, змініть постійні посилання, перейшовши до WordPress &gt; Налаштування &gt; Постійні посилання та натиснувши «Зберегти». Це повинно повернути посилання у нормальний стан.</p>\n<h4>Приклади даних</h4>\n<p>WooCommerce поставляється з деякими зразковими даними, які можна використовувати для перегляду вигляду продуктів; імпортуйте sample_products.xml через <a href=\"https://wordpress.org/plugins/wordpress-importer/\" rel=\"ugc\">імпортер WordPress</a>. Ви також можете використовувати основний <a href=\"https://woocommerce.com/document/product-csv-importer-exporter/?utm_source=wp%20org%20repo%20listing&amp;utm_content=3.6\" rel=\"nofollow ugc\">імпортер CSV</a> або наш <a href=\"https://woocommerce.com/products/product-csv-import-suite/?utm_source=wp%20org%20repo%20listing&amp;utm_content=3.6\" rel=\"nofollow ugc\">розширення CSV Import Suite</a> для імпорту sample_products.csv</p>\n\";s:3:\"faq\";s:10410:\"\n<dt id=\"where%20can%20i%20find%20woocommerce%20documentation%20and%20user%20guides%3F\">\nДе я зможу знайти документацію WooCommerce та посібник користувача?\n</h4>\n<p>\n<p>Для отримання допомоги з налаштування та конфігурування WooCommerce, будь ласка, звертайтеся до <a href=\"https://woocommerce.com/documentation/plugins/woocommerce/getting-started/?utm_medium=referral&amp;utm_source=wordpress.org&amp;utm_campaign=wp_org_repo_listing\" rel=\"nofollow ugc\">Початок роботи</a> та <a href=\"https://woocommerce.com/guides/new-store/?utm_medium=referral&amp;utm_source=wordpress.org&amp;utm_campaign=wp_org_repo_listing\" rel=\"nofollow ugc\">Посібник нового власника магазину WooCommerce</a>.</p>\n<p>Для розширення або створення тем для WooCommerce, див. нашу <a href=\"https://github.com/woocommerce/woocommerce/tree/trunk/docs\" rel=\"nofollow ugc\">документацію</a>, а також <a href=\"https://github.com/woocommerce/woocommerce/blob/trunk/docs/extension-development/extension-development-best-practices.md\" rel=\"nofollow ugc\">Найкращі практики розробки плагінів</a>.</p>\n</p>\n<dt id=\"where%20can%20i%20get%20help%20or%20talk%20to%20other%20users%20about%20woocommerce%20core%3F\">\nДе можна отримати допомогу або обговорити WooCommerce Core з іншими користувачами?\n</h4>\n<p>\n<p>Якщо ви застрягли, ви можете попросити допомоги на <a href=\"https://wordpress.org/support/plugin/woocommerce/?utm_medium=referral&amp;utm_source=wordpress.org&amp;utm_campaign=wp_org_repo_listing\" rel=\"ugc\">Форумі підтримки WooCommerce</a>, дотримуючись <a href=\"https://wordpress.org/support/topic/guide-to-the-woocommerce-forum/?utm_medium=referral&amp;utm_source=wordpress.org&amp;utm_campaign=wp_org_repo_listing\" rel=\"ugc\">цих вказівок</a>, звернутися через <a href=\"https://woocommerce.com/community-slack/?utm_medium=referral&amp;utm_source=wordpress.org&amp;utm_campaign=wp_org_repo_listing\" rel=\"nofollow ugc\">Slack спільноту WooCommerce</a>, або опублікувати в <a href=\"https://www.facebook.com/groups/advanced.woocommerce?utm_medium=referral&amp;utm_source=wordpress.org&amp;utm_campaign=wp_org_repo_listing\" rel=\"nofollow ugc\">групі спільноти WooCommerce</a> на Facebook.</p>\n</p>\n<dt id=\"where%20can%20i%20get%20help%20for%20extensions%20i%20have%20purchased%20from%20the%20woocommerce%20marketplace%3F\">\nДе я можу отримати допомогу щодо розширень, придбаних на WooCommerce Marketplace?\n</h4>\n<p>\n<p>Щоб отримати допомогу щодо платних доповнень із магазину WooCommerce, спочатку перегляньте наш <a href=\"https://woocommerce.com/document/woocommerce-self-service-guide/\" rel=\"nofollow ugc\">посібник із самостійного пошуку та усунення несправностей</a>. Якщо проблема не зникне, будь ласка, зареєструйте заявку на підтримку через <a href=\"https://woocommerce.com/my-account/create-a-ticket/\" rel=\"nofollow ugc\">нашу службу підтримки</a>. Наші спеціалісти із задоволенням нададуть вам відповідь протягом 24 годин.</p>\n</p>\n<dt id=\"i%E2%80%99m%20having%20trouble%20logging%20in%20to%20woocommerce.com%20%E2%80%93%20what%20now%3F\">\nУ мене виникли проблеми при вході на WooCommerce.com, що робити?\n</h4>\n<p>\n<p>Спочатку вирішіть загальні проблеми з входом за допомогою цього корисного <a href=\"https://woocommerce.com/document/log-into-woocommerce-com-with-wordpress-com/?utm_medium=referral&amp;utm_source=wordpress.org&amp;utm_campaign=wp_org_repo_listing\" rel=\"nofollow ugc\">посібника крок за кроком</a>. До цих пір не працює? <a href=\"https://woocommerce.com/contact-us/?utm_medium=referral&amp;utm_source=wordpress.org&amp;utm_campaign=wp_org_repo_listing\" rel=\"nofollow ugc\">Зв&#8217;яжіться з нами</a>.</p>\n</p>\n<dt id=\"will%20woocommerce%20work%20with%20my%20theme%3F\">\nЧи працюватиме WooCommerce з моєю темою?\n</h4>\n<p>\n<p>Так! WooCommerce буде працювати з будь-якою темою, але можуть знадобитися додаткові налаштування теми. Якщо ви шукаєте тему з поглибленою інтеграцією WooCommerce, ми рекомендуємо <a href=\"https://woocommerce.com/storefront/?utm_medium=referral&amp;utm_source=wordpress.org&amp;utm_campaign=wp_org_repo_listing\" rel=\"nofollow ugc\">Storefront</a>.</p>\n</p>\n<dt id=\"how%20do%20i%20update%20woocommerce%3F\">\nЯк оновити WooCommerce?\n</h4>\n<p>\n<p>Ми маємо детальний посібник <a href=\"https://woocommerce.com/document/how-to-update-woocommerce/?utm_medium=referral&amp;utm_source=wordpress.org&amp;utm_campaign=wp_org_repo_listing\" rel=\"nofollow ugc\">по оновленню WooCommerce</a>.</p>\n</p>\n<dt id=\"my%20site%20broke%20%E2%80%93%20what%20do%20i%20do%3F\">\nМій сайт перестав працювати, що мені робити?\n</h4>\n<p>\n<p>Почніть з діагностики проблеми за допомогою нашого зручного <a href=\"https://woocommerce.com/documentation/get-help/troubleshooting-get-help/?utm_medium=referral&amp;utm_source=wordpress.org&amp;utm_campaign=wp_org_repo_listing\" rel=\"nofollow ugc\">посібника по усуненню неполадок</a>.</p>\n<p>Якщо ви помітили помилку після оновлення теми чи плагіну, між ними та WooCommerce можуть виникнути проблеми сумісності. Якщо проблема з’явилася після оновлення WooCommerce, може виникнути конфлікт між WooCommerce та застарілою темою чи плагіном.</p>\n<p>У обох випадках ми рекомендуємо виконати тест на конфлікти за допомогою <a href=\"https://woocommerce.com/document/troubleshooting-using-health-check/?utm_medium=referral&amp;utm_source=wordpress.org&amp;utm_campaign=wp_org_repo_listing\" rel=\"nofollow ugc\">Health Check</a> (що дозволяє вимкнути теми та плагіни без впливу на відвідувачів) або вирішити проблему шляхом використання <a href=\"https://woocommerce.com/document/how-to-test-for-conflicts/#section-3?utm_medium=referral&amp;utm_source=wordpress.org&amp;utm_campaign=wp_org_repo_listing\" rel=\"nofollow ugc\">стендового сайту</a>.</p>\n</p>\n<dt id=\"where%20can%20i%20report%20bugs%3F\">\nДе я можу повідомити про помилки?\n</h4>\n<p>\n<p>Повідомляйте про помилки через <a href=\"https://github.com/woocommerce/woocommerce/issues?utm_medium=referral&amp;utm_source=wordpress.org&amp;utm_campaign=wp_org_repo_listing\" rel=\"nofollow ugc\">репозиторій WooCommerce GitHub</a>. Крім того, ви можете відправляти повідомлення на нашому форумі підтримки. Обов&#8217;язково перевірте на форумах, чи не повідомляли інші користувачі про подібну помилку раніше.</p>\n</p>\n<dt id=\"where%20can%20i%20request%20new%20features%2C%20themes%2C%20and%20extensions%3F\">\nДе я можу запросити нові функції, теми та розширення?\n</h4>\n<p>\n<p>Робіть запити на нові функції та розширення, а також голосуйте за існуючі пропозиції на нашій офіційній <a href=\"https://woocommerce.com/feature-requests/woocommerce?utm_medium=referral&amp;utm_source=wordpress.org&amp;utm_campaign=wp_org_repo_listing\" rel=\"nofollow ugc\">дошці запитів нових функцій</a>. Наші фахівці регулярно переглядають запити та вважають їх корисними для планування розробки продуктів.</p>\n</p>\n<dt id=\"woocommerce%20is%20awesome%21%20can%20i%20contribute%3F\">\nWooCommerce чудовий! Чи можу я допомогти?\n</h4>\n<p>\n<p>Так, можете! Приєднуйтесь до нашого <a href=\"https://github.com/woocommerce/woocommerce/?utm_medium=referral&amp;utm_source=wordpress.org&amp;utm_campaign=wp_org_repo_listing\" rel=\"nofollow ugc\">репозиторія GitHub</a> і слідкуйте за <a href=\"https://woocommerce.wordpress.com/?utm_medium=referral&amp;utm_source=wordpress.org&amp;utm_campaign=wp_org_repo_listing\" rel=\"nofollow ugc\">блогом, присвячений розробкам</a>, щоб бути в курсі всіх новин проекту.</p>\n</p>\n<dt id=\"where%20can%20i%20find%20rest%20api%20documentation%3F\">\nДе я можу знайти документацію по REST API?\n</h4>\n<p>\n<p>Велика <a href=\"https://woocommerce.github.io/woocommerce-rest-api-docs/?utm_medium=referral&amp;utm_source=wordpress.org&amp;utm_campaign=wp_org_repo_listing\" rel=\"nofollow ugc\">документація по WooCommerce REST API</a> доступна в GitHub.</p>\n</p>\n<dt id=\"my%20question%20is%20not%20listed%20here.%20where%20can%20i%20find%20more%20answers%3F\">\nМого питання немає в цьому переліку. Де я можу знайти більше відповідей?\n</h4>\n<p>\n<p>Дізнайтеся більше в розділі <a href=\"https://woocommerce.com/document/frequently-asked-questions/?utm_medium=referral&amp;utm_source=wordpress.org&amp;utm_campaign=wp_org_repo_listing\" rel=\"nofollow ugc\">Поширені питання</a>.</p>\n</p>\n\n\";s:9:\"changelog\";s:30979:\"<h4>10.7.0 2026-04-14</h4>\n<p><strong>WooCommerce</strong></p>\n<ul>\n<li>Fix &#8211; Added try/catch guards to store notices to prevent fatal errors when context is missing. <a href=\"https://github.com/woocommerce/woocommerce/pull/63402\" rel=\"nofollow ugc\">#63402</a></li>\n<li>Fix &#8211; Add missing session methods to StoreApi SessionHandler for compatibility with WC_Session_Handler. <a href=\"https://github.com/woocommerce/woocommerce/pull/63606\" rel=\"nofollow ugc\">#63606</a></li>\n<li>Fix &#8211; Add nonce verification to <code>product_ordering</code> and <code>term_ordering</code> AJAX handlers to prevent CSRF. <a href=\"https://github.com/woocommerce/woocommerce/pull/63422\" rel=\"nofollow ugc\">#63422</a></li>\n<li>Fix &#8211; Address deprecation warnings in feedback button. <a href=\"https://github.com/woocommerce/woocommerce/pull/63554\" rel=\"nofollow ugc\">#63554</a></li>\n<li>Fix &#8211; Always show radio for payment methods on checkout. <a href=\"https://github.com/woocommerce/woocommerce/pull/63351\" rel=\"nofollow ugc\">#63351</a></li>\n<li>Fix &#8211; Fix &#8211; Show &#8216;Billing address&#8217; instead of &#8216;Billing and shipping address&#8217; when Local Pickup is selected and shipping is forced to the billing address. <a href=\"https://github.com/woocommerce/woocommerce/pull/58220\" rel=\"nofollow ugc\">#58220</a></li>\n<li>Fix &#8211; Fix a bug with the Store Email personalization tag that caused it to always return the admin email instead of using the <code>get_from_address</code> method from the email object context <a href=\"https://github.com/woocommerce/woocommerce/pull/63605\" rel=\"nofollow ugc\">#63605</a></li>\n<li>Fix &#8211; Fix add to cart not working on stale nonces on cached pages <a href=\"https://github.com/woocommerce/woocommerce/pull/62892\" rel=\"nofollow ugc\">#62892</a></li>\n<li>Fix &#8211; Fix a small punctuation issue at the LYS page. <a href=\"https://github.com/woocommerce/woocommerce/pull/63874\" rel=\"nofollow ugc\">#63874</a></li>\n<li>Fix &#8211; Fix attribute matching for non-ASCII characters in product CSV importer <a href=\"https://github.com/woocommerce/woocommerce/pull/62963\" rel=\"nofollow ugc\">#62963</a></li>\n<li>Fix &#8211; Fix attribute terms REST API writing menu_order to wrong meta key. <a href=\"https://github.com/woocommerce/woocommerce/pull/63390\" rel=\"nofollow ugc\">#63390</a></li>\n<li>Fix &#8211; Fix cart: prevent false &#8220;Quantity changed to 1&#8221; notices and add optimistic removal feedback <a href=\"https://github.com/woocommerce/woocommerce/pull/63403\" rel=\"nofollow ugc\">#63403</a></li>\n<li>Fix &#8211; Fix Cart and Checkout block editor detection for post-new.php and other custom editor contexts. <a href=\"https://github.com/woocommerce/woocommerce/pull/63759\" rel=\"nofollow ugc\">#63759</a></li>\n<li>Fix &#8211; Fix console warnings in the editor when using cart and checkout blocks. <a href=\"https://github.com/woocommerce/woocommerce/pull/63541\" rel=\"nofollow ugc\">#63541</a></li>\n<li>Fix &#8211; Fix customer note email preview using wrong note text and missing newline support in admin order note personalization tag. <a href=\"https://github.com/woocommerce/woocommerce/pull/63459\" rel=\"nofollow ugc\">#63459</a></li>\n<li>Fix &#8211; Fix Customers Reports advanced filters (email, username, name) by consolidating autocompleter customer IDs into customers/customers_exclude params in the Controller, and add customers_exclude support. <a href=\"https://github.com/woocommerce/woocommerce/pull/63232\" rel=\"nofollow ugc\">#63232</a></li>\n<li>Fix &#8211; Fix dashboard status widget not showing after task list completion by adding a DeprecatedOptions bridge for woocommerce_task_list_complete. <a href=\"https://github.com/woocommerce/woocommerce/pull/63522\" rel=\"nofollow ugc\">#63522</a></li>\n<li>Fix &#8211; Fix duplicate &#8220;Fulfillment updated&#8221; order notes caused by redundant save_meta_data() call in OrderFulfillmentsRestController. <a href=\"https://github.com/woocommerce/woocommerce/pull/63544\" rel=\"nofollow ugc\">#63544</a></li>\n<li>Fix &#8211; Fixed sold individually validation on shortcode cart and checkout pages. Products marked as &#8220;Sold Individually&#8221; after being added to cart now have quantity automatically reduced to 1 with correct totals calculation. <a href=\"https://github.com/woocommerce/woocommerce/pull/62293\" rel=\"nofollow ugc\">#62293</a></li>\n<li>Fix &#8211; Fixes issue where actions for shipping extension in onboarding didn&#8217;t display. <a href=\"https://github.com/woocommerce/woocommerce/pull/63348\" rel=\"nofollow ugc\">#63348</a></li>\n<li>Fix &#8211; Fix extra padding on analytics tables, dashboard charts, leaderboards, and store alerts on WordPress 7.0 by setting Card/CardBody size to &#8220;none&#8221;. <a href=\"https://github.com/woocommerce/woocommerce/pull/63826\" rel=\"nofollow ugc\">#63826</a></li>\n<li>Fix &#8211; Fix floating point precision error in REST API v4 refund amount validation that caused valid refunds to be rejected. <a href=\"https://github.com/woocommerce/woocommerce/pull/63667\" rel=\"nofollow ugc\">#63667</a></li>\n<li>Fix &#8211; Fix fulfillment created email subject and heading to use correct plural form when shipment contains multiple items. <a href=\"https://github.com/woocommerce/woocommerce/pull/63765\" rel=\"nofollow ugc\">#63765</a></li>\n<li>Fix &#8211; Fix incorrect new hook names in deprecated filter hooks mapping for order refund amount and reason. <a href=\"https://github.com/woocommerce/woocommerce/pull/56511\" rel=\"nofollow ugc\">#56511</a></li>\n<li>Fix &#8211; Fix insufficient color contrast for status indicators on the System Status page to meet WCAG 2.2 AA requirements. <a href=\"https://github.com/woocommerce/woocommerce/pull/63746\" rel=\"nofollow ugc\">#63746</a></li>\n<li>Fix &#8211; Fix insufficient colour contrast in Dashboard Status widget link text to meet WCAG 2.2 AA requirements. <a href=\"https://github.com/woocommerce/woocommerce/pull/63521\" rel=\"nofollow ugc\">#63521</a></li>\n<li>Fix &#8211; Fix invalid JSON Schema in MCP tool definitions: convert date-time type to proper string+format, deduplicate enum values, handle mixed/action/unrecognized types, normalize array types, recursively sanitize nested schemas, sanitize output schemas, and strip boolean required from nested properties. <a href=\"https://github.com/woocommerce/woocommerce/pull/63811\" rel=\"nofollow ugc\">#63811</a></li>\n<li>Fix &#8211; Fix invalid JSON Schema in MCP tool definitions: convert date-time type to proper string+format and deduplicate enum values. <a href=\"https://github.com/woocommerce/woocommerce/pull/63811\" rel=\"nofollow ugc\">#63811</a></li>\n<li>Fix &#8211; Fix math expressions being rejected in the flat rate shipping cost field <a href=\"https://github.com/woocommerce/woocommerce/pull/63453\" rel=\"nofollow ugc\">#63453</a></li>\n<li>Fix &#8211; Fix Mini-Cart badge becoming invisible after client-side navigation. <a href=\"https://github.com/woocommerce/woocommerce/pull/63014\" rel=\"nofollow ugc\">#63014</a></li>\n<li>Fix &#8211; Fix misaligned order rows on the edit order screen when Cost of Goods Sold is enabled. <a href=\"https://github.com/woocommerce/woocommerce/pull/63396\" rel=\"nofollow ugc\">#63396</a></li>\n<li>Fix &#8211; Fix older PayPal Standard orders failing shipping callbacks when the request has no token by checking for token meta before validating the token parameter. <a href=\"https://github.com/woocommerce/woocommerce/pull/63885\" rel=\"nofollow ugc\">#63885</a></li>\n<li>Fix &#8211; Fix order meta box action buttons stacking poorly on smaller viewports (~1200px) with WordPress 7.0. <a href=\"https://github.com/woocommerce/woocommerce/pull/63837\" rel=\"nofollow ugc\">#63837</a></li>\n<li>Fix &#8211; Fix PayPal Standard webhook handling for invalid links. <a href=\"https://github.com/woocommerce/woocommerce/pull/63886\" rel=\"nofollow ugc\">#63886</a></li>\n<li>Fix &#8211; Fix PHP &#8220;Undefined property&#8221; warnings in <code>set_order_props_from_data</code> when HPOS Data Caching is enabled and cached objects have missing properties. <a href=\"https://github.com/woocommerce/woocommerce/pull/63295\" rel=\"nofollow ugc\">#63295</a></li>\n<li>Fix &#8211; Fix REST v4 API silently corrupting password and API key fields with special characters <a href=\"https://github.com/woocommerce/woocommerce/pull/63597\" rel=\"nofollow ugc\">#63597</a></li>\n<li>Fix &#8211; Fix selectWoo not initializing on the layered nav dropdown widget when using the OR query type. <a href=\"https://github.com/woocommerce/woocommerce/pull/63275\" rel=\"nofollow ugc\">#63275</a></li>\n<li>Fix &#8211; Fix session cookie when guest creates account during checkout. <a href=\"https://github.com/woocommerce/woocommerce/pull/63335\" rel=\"nofollow ugc\">#63335</a></li>\n<li>Fix &#8211; Fix settings password fields silently stripping characters that resemble percent-encoded sequences. <a href=\"https://github.com/woocommerce/woocommerce/pull/63595\" rel=\"nofollow ugc\">#63595</a></li>\n<li>Fix &#8211; Fix styling issues with WP 7.0 <a href=\"https://github.com/woocommerce/woocommerce/pull/63824\" rel=\"nofollow ugc\">#63824</a></li>\n<li>Fix &#8211; Fix System Status template override detection to show actual runtime behavior, including plugin filter overrides. <a href=\"https://github.com/woocommerce/woocommerce/pull/62964\" rel=\"nofollow ugc\">#62964</a></li>\n<li>Fix &#8211; Fix template overrides with missing version headers being incorrectly flagged as outdated, and render overrides as individual rows in the System Status report for improved readability. <a href=\"https://github.com/woocommerce/woocommerce/pull/63460\" rel=\"nofollow ugc\">#63460</a></li>\n<li>Fix &#8211; Fix the misalignment of the set new/lost password fields for twenty twenty and twenty twenty one themes. <a href=\"https://github.com/woocommerce/woocommerce/pull/59273\" rel=\"nofollow ugc\">#59273</a></li>\n<li>Fix &#8211; Fix undefined site_url variable in robots_txt <a href=\"https://github.com/woocommerce/woocommerce/pull/63589\" rel=\"nofollow ugc\">#63589</a></li>\n<li>Fix &#8211; Fix variable products not working when name is different than the slug <a href=\"https://github.com/woocommerce/woocommerce/pull/63736\" rel=\"nofollow ugc\">#63736</a></li>\n<li>Fix &#8211; Fix _load_textdomain_just_in_time warning in FulfillmentsController by checking feature option directly instead of using FeaturesController::feature_is_enabled() before init action. <a href=\"https://github.com/woocommerce/woocommerce/pull/63893\" rel=\"nofollow ugc\">#63893</a></li>\n<li>Fix &#8211; Make select focused state consistent with other input types <a href=\"https://github.com/woocommerce/woocommerce/pull/63608\" rel=\"nofollow ugc\">#63608</a></li>\n<li>Fix &#8211; Make sure that woocommerce_email_templates_*_post_id options are properly deleted when woo_email posts are removed in non-admin environments, such as WP-CLI. <a href=\"https://github.com/woocommerce/woocommerce/pull/63500\" rel=\"nofollow ugc\">#63500</a></li>\n<li>Fix &#8211; Make username and password optional in V4 Customers REST API regardless of store registration settings. <a href=\"https://github.com/woocommerce/woocommerce/pull/63536\" rel=\"nofollow ugc\">#63536</a></li>\n<li>Fix &#8211; Make zone locations optional in the V4 Shipping Zones REST API schema so that &#8220;Everywhere&#8221; zones can be created without providing a locations array. <a href=\"https://github.com/woocommerce/woocommerce/pull/63685\" rel=\"nofollow ugc\">#63685</a></li>\n<li>Fix &#8211; Mini-Cart: use server-computed item count when third-party filters modify <code>woocommerce_cart_contents_count</code>. <a href=\"https://github.com/woocommerce/woocommerce/pull/63378\" rel=\"nofollow ugc\">#63378</a></li>\n<li>Fix &#8211; Prevent &#8220;Order again&#8221; button showing on order confirmation page <a href=\"https://github.com/woocommerce/woocommerce/pull/63499\" rel=\"nofollow ugc\">#63499</a></li>\n<li>Fix &#8211; Prevent Activity panel abbreviated notification SlotFill from triggering repeated re-renders by creating the slot at module scope. <a href=\"https://github.com/woocommerce/woocommerce/pull/63830\" rel=\"nofollow ugc\">#63830</a></li>\n<li>Fix &#8211; Prevent draft products from being accessible via Store API and redact content for password-protected products <a href=\"https://github.com/woocommerce/woocommerce/pull/63466\" rel=\"nofollow ugc\">#63466</a></li>\n<li>Fix &#8211; Prevent fatal error when FTP filesystem connection fails during logging operations. <a href=\"https://github.com/woocommerce/woocommerce/pull/63298\" rel=\"nofollow ugc\">#63298</a></li>\n<li>Fix &#8211; Prevent mini-cart drawer having a white background and use page background instead <a href=\"https://github.com/woocommerce/woocommerce/pull/63758\" rel=\"nofollow ugc\">#63758</a></li>\n<li>Fix &#8211; Prevent stored XSS on order notes added via REST API v4 <a href=\"https://github.com/woocommerce/woocommerce/pull/63661\" rel=\"nofollow ugc\">#63661</a></li>\n<li>Fix &#8211; Skip initial save of POS store name setting so emails use the current site name instead of the stale &#8220;My WordPress Site&#8221; default. <a href=\"https://github.com/woocommerce/woocommerce/pull/63505\" rel=\"nofollow ugc\">#63505</a></li>\n<li>Fix &#8211; Update slug sanitize callback to use sanitize_slug <a href=\"https://github.com/woocommerce/woocommerce/pull/63342\" rel=\"nofollow ugc\">#63342</a></li>\n<li>Fix &#8211; Wrong escaping of &#8220;&amp;&#8221; character in product name in img alt tag in cart and checkout pages <a href=\"https://github.com/woocommerce/woocommerce/pull/63637\" rel=\"nofollow ugc\">#63637</a></li>\n<li>Fix &#8211; Add to Cart + Options: Ensure attributes with spaces and special characters work well in dropdown mode <a href=\"https://github.com/woocommerce/woocommerce/pull/64037\" rel=\"nofollow ugc\">#64037</a></li>\n<li>Fix &#8211; Fix Add to Cart button not visible when displaying a Single Product block with a variation with only one product left <a href=\"https://github.com/woocommerce/woocommerce/pull/63947\" rel=\"nofollow ugc\">#63947</a></li>\n<li>Fix &#8211; Fix cart shipping and totals stuck as loading when removing bundled products <a href=\"https://github.com/woocommerce/woocommerce/pull/64000\" rel=\"nofollow ugc\">#64000</a></li>\n<li>Fix &#8211; Fix issues when Product Gallery was used inside the Product block <a href=\"https://github.com/woocommerce/woocommerce/pull/63976\" rel=\"nofollow ugc\">#63976</a></li>\n<li>Fix &#8211; Fix settings page label vertical alignment on WordPress 7.0 where increased form element height caused labels to sit too high relative to their fields. <a href=\"https://github.com/woocommerce/woocommerce/pull/63924\" rel=\"nofollow ugc\">#63924</a></li>\n<li>Fix &#8211; Fix entity-encoded HTML in <code>item_data</code> being incorrectly decoded during mini-cart rendering. <a href=\"https://github.com/woocommerce/woocommerce/pull/64122\" rel=\"nofollow ugc\">#64122</a></li>\n<li>Fix &#8211; Fix fatal error on Payments settings page when <code>woocommerce_gateway_order</code> option contains legacy integer keys. <a href=\"https://github.com/woocommerce/woocommerce/pull/64061\" rel=\"nofollow ugc\">#64061</a></li>\n<li>Fix &#8211; Fix inconsistent icon spacing in the customer account block header on mobile. <a href=\"https://github.com/woocommerce/woocommerce/pull/64126\" rel=\"nofollow ugc\">#64126</a></li>\n<li>Fix &#8211; Fix shipping provider filter on orders list using wrong meta key, causing no results to appear. <a href=\"https://github.com/woocommerce/woocommerce/pull/64101\" rel=\"nofollow ugc\">#64101</a></li>\n<li>Fix &#8211; Fix tracking number lookup breaking when custom shipping provider definitions contain non-string values. <a href=\"https://github.com/woocommerce/woocommerce/pull/64075\" rel=\"nofollow ugc\">#64075</a></li>\n<li>Add &#8211; Add custom shipping providers settings UI and shipping provider filter for the orders list. <a href=\"https://github.com/woocommerce/woocommerce/pull/63879\" rel=\"nofollow ugc\">#63879</a></li>\n<li>Add &#8211; Add description for COD enable_for_methods field in v4 settings API. <a href=\"https://github.com/woocommerce/woocommerce/pull/63767\" rel=\"nofollow ugc\">#63767</a></li>\n<li>Add &#8211; Add design-aligned grouped settings schemas for offline payment gateways (cheque, BACS, COD) in the v4 settings API. <a href=\"https://github.com/woocommerce/woocommerce/pull/63734\" rel=\"nofollow ugc\">#63734</a></li>\n<li>Add &#8211; Add embeddable _links for upsells, cross-sells, and related products to Store API Products endpoint. <a href=\"https://github.com/woocommerce/woocommerce/pull/62603\" rel=\"nofollow ugc\">#62603</a></li>\n<li>Add &#8211; Add export column and item filters to Revenue Stats, Taxes, and Variations report controllers, and forward selected currency from URL query params into the export job payload. <a href=\"https://github.com/woocommerce/woocommerce/pull/63618\" rel=\"nofollow ugc\">#63618</a></li>\n<li>Add &#8211; Add formatted_weight and formatted_dimensions to Store API ProductSchema <a href=\"https://github.com/woocommerce/woocommerce/pull/63405\" rel=\"nofollow ugc\">#63405</a></li>\n<li>Add &#8211; Add notice to Cart/Checkout blocks front-end to show notices about incompatible plugins to admin users. <a href=\"https://github.com/woocommerce/woocommerce/pull/62242\" rel=\"nofollow ugc\">#62242</a></li>\n<li>Add &#8211; Add order notes for fulfillment lifecycle events (created, updated, deleted, status changes) to improve order history tracking and auditability. <a href=\"https://github.com/woocommerce/woocommerce/pull/63516\" rel=\"nofollow ugc\">#63516</a></li>\n<li>Add &#8211; Add reset notification email content action to the email editor, allowing users to reset email content to the original plugin-distributed state. <a href=\"https://github.com/woocommerce/woocommerce/pull/63558\" rel=\"nofollow ugc\">#63558</a></li>\n<li>Add &#8211; Add server-side auto-selection of email template when template_id is omitted in send_email endpoint. <a href=\"https://github.com/woocommerce/woocommerce/pull/63556\" rel=\"nofollow ugc\">#63556</a></li>\n<li>Add &#8211; Add ShipStation and Packlink as shipping extension options in the Core Profiler for supported countries (ShipStation: CA, DE, GB, AU, NZ; Packlink: FR, ES, IT, NL, AT, BE). <a href=\"https://github.com/woocommerce/woocommerce/pull/63385\" rel=\"nofollow ugc\">#63385</a></li>\n<li>Add &#8211; Add ShipStation and Packlink PRO as recommended shipping solutions on the Shipping settings page, filtered by store country. <a href=\"https://github.com/woocommerce/woocommerce/pull/63383\" rel=\"nofollow ugc\">#63383</a></li>\n<li>Add &#8211; Add smaller image options for product images in srcset to reduce bandwidth/load time on cart/checkout pages <a href=\"https://github.com/woocommerce/woocommerce/pull/63731\" rel=\"nofollow ugc\">#63731</a></li>\n<li>Add &#8211; Add support for notice data in recommended payment methods, enabling payment gateways to surface requirement warnings during onboarding. <a href=\"https://github.com/woocommerce/woocommerce/pull/63854\" rel=\"nofollow ugc\">#63854</a></li>\n<li>Add &#8211; Add telemetry for fulfillment feature adoption and usage tracking <a href=\"https://github.com/woocommerce/woocommerce/pull/63820\" rel=\"nofollow ugc\">#63820</a></li>\n<li>Add &#8211; Add unified shipping partner Tracks events (impression, click, install, activate) in the Core Profiler onboarding flow. <a href=\"https://github.com/woocommerce/woocommerce/pull/63439\" rel=\"nofollow ugc\">#63439</a></li>\n<li>Add &#8211; Add woocommerce_delete_expired_draft_orders_batch_size filter to make draft order cleanup batch size configurable <a href=\"https://github.com/woocommerce/woocommerce/pull/63740\" rel=\"nofollow ugc\">#63740</a></li>\n<li>Add &#8211; Add <code>woocommerce_email_block_template_html</code> filter to allow customization of email block template HTML before it is saved. <a href=\"https://github.com/woocommerce/woocommerce/pull/63607\" rel=\"nofollow ugc\">#63607</a></li>\n<li>Add &#8211; Apply <code>woocommerce_variation_option_name</code> filter in ProductItemTrait, allowing third-parties to optionally add relevant information to variation option names. <a href=\"https://github.com/woocommerce/woocommerce/pull/63673\" rel=\"nofollow ugc\">#63673</a></li>\n<li>Add &#8211; Exclude WCPay test orders from analytics data to prevent test transactions from polluting reports. <a href=\"https://github.com/woocommerce/woocommerce/pull/63550\" rel=\"nofollow ugc\">#63550</a></li>\n<li>Add &#8211; Show preview products and placeholder cards in the email editor for product collection blocks when the store has no products <a href=\"https://github.com/woocommerce/woocommerce/pull/63612\" rel=\"nofollow ugc\">#63612</a></li>\n<li>Add &#8211; Add myPOS and Evergreen Payments as official payment partners. <a href=\"https://github.com/woocommerce/woocommerce/pull/64097\" rel=\"nofollow ugc\">#64097</a></li>\n<li>Update &#8211; Accept top-level enabled, title, description, and order fields in the v4 payment gateway settings PUT endpoint. This aligns the PUT shape with the GET response, enabling @wordpress/core-data to track dirty state correctly. The values parameter remains supported for backwards compatibility. <a href=\"https://github.com/woocommerce/woocommerce/pull/63714\" rel=\"nofollow ugc\">#63714</a></li>\n<li>Update &#8211; Add weight and dimensions to Store API ProductSchema / Products endpoint. <a href=\"https://github.com/woocommerce/woocommerce/pull/63334\" rel=\"nofollow ugc\">#63334</a></li>\n<li>Update &#8211; Change Cache Product Objects feature default plugin compatibility to COMPATIBLE so extensions that haven&#8217;t explicitly declared compatibility are no longer shown as incompatible. <a href=\"https://github.com/woocommerce/woocommerce/pull/63243\" rel=\"nofollow ugc\">#63243</a></li>\n<li>Update &#8211; Disable HPOS sync-on-read by default and add admin notice for affected sites. <a href=\"https://github.com/woocommerce/woocommerce/pull/63175\" rel=\"nofollow ugc\">#63175</a></li>\n<li>Update &#8211; Extract &#8220;get_primed_visible_children()&#8221; helper in &#8220;WC_Product_Grouped&#8221;. <a href=\"https://github.com/woocommerce/woocommerce/pull/63284\" rel=\"nofollow ugc\">#63284</a></li>\n<li>Update &#8211; Make checkout item quantity round and inherit theme colours <a href=\"https://github.com/woocommerce/woocommerce/pull/63007\" rel=\"nofollow ugc\">#63007</a></li>\n<li>Update &#8211; Refactor cart, cart-link, mini-cart and checkout blocks to use isPreviewMode flag <a href=\"https://github.com/woocommerce/woocommerce/pull/63313\" rel=\"nofollow ugc\">#63313</a></li>\n<li>Update &#8211; Register fulfillments data store via WC_Data_Store for extensibility, allowing extensions to provide custom data store implementations. <a href=\"https://github.com/woocommerce/woocommerce/pull/63485\" rel=\"nofollow ugc\">#63485</a></li>\n<li>Update &#8211; Replace Facebook and Meta Ads/Kliken with Reddit and Snapchat in the Marketing Overview channels list, reorder the sales channels, and update the Google for WooCommerce description <a href=\"https://github.com/woocommerce/woocommerce/pull/63416\" rel=\"nofollow ugc\">#63416</a></li>\n<li>Update &#8211; Standardize closing support text across all customer-facing block email templates. <a href=\"https://github.com/woocommerce/woocommerce/pull/63463\" rel=\"nofollow ugc\">#63463</a></li>\n<li>Update &#8211; Textarea inputs on Checkout will now have the correct placeholder colour on light themes <a href=\"https://github.com/woocommerce/woocommerce/pull/63539\" rel=\"nofollow ugc\">#63539</a></li>\n<li>Update &#8211; Update &#8216;on hold&#8217; email copy in block email editor to be more neutral for services and virtual products. <a href=\"https://github.com/woocommerce/woocommerce/pull/63496\" rel=\"nofollow ugc\">#63496</a></li>\n<li>Update &#8211; Admin styling adjustments with WordPress 7.0 <a href=\"https://github.com/woocommerce/woocommerce/pull/64027\" rel=\"nofollow ugc\">#64027</a></li>\n<li>Dev &#8211; Convert e2e-pw API test files to TypeScript. <a href=\"https://github.com/woocommerce/woocommerce/pull/63314\" rel=\"nofollow ugc\">#63314</a></li>\n<li>Dev &#8211; Convert e2e-pw utils to TypeScript. <a href=\"https://github.com/woocommerce/woocommerce/pull/63318\" rel=\"nofollow ugc\">#63318</a></li>\n<li>Dev &#8211; Convert fixtures and utils of the e2e-pw directory to TypeScript. <a href=\"https://github.com/woocommerce/woocommerce/pull/63315\" rel=\"nofollow ugc\">#63315</a></li>\n<li>Dev &#8211; Introduce a new performance skill focused on effectively using caching priming APIs. <a href=\"https://github.com/woocommerce/woocommerce/pull/63706\" rel=\"nofollow ugc\">#63706</a></li>\n<li>Dev &#8211; Introduce end-to-end tests for PayPal Standard (enablement flow). <a href=\"https://github.com/woocommerce/woocommerce/pull/63068\" rel=\"nofollow ugc\">#63068</a></li>\n<li>Dev &#8211; Introduce end-to-end tests for PayPal Standard (Jetpack onboarding flow). <a href=\"https://github.com/woocommerce/woocommerce/pull/62982\" rel=\"nofollow ugc\">#62982</a></li>\n<li>Dev &#8211; Migrate dinero.js from v1.9.1 to v2.0.0 in WooCommerce Blocks. <a href=\"https://github.com/woocommerce/woocommerce/pull/63543\" rel=\"nofollow ugc\">#63543</a></li>\n<li>Dev &#8211; Consolidate get_shipping_providers and get_shipping_providers_object into a single method that always returns AbstractShippingProvider instances. <a href=\"https://github.com/woocommerce/woocommerce/pull/64102\" rel=\"nofollow ugc\">#64102</a></li>\n<li>Tweak &#8211; Add data-cart-item-key attribute to cart line item row block. <a href=\"https://github.com/woocommerce/woocommerce/pull/63090\" rel=\"nofollow ugc\">#63090</a></li>\n<li>Tweak &#8211; Fulfillment UI/UX minor tweaks: clickable card headers, reduced padding, copy confirmation, provider label resolution, and tracking URL auto-update. <a href=\"https://github.com/woocommerce/woocommerce/pull/63899\" rel=\"nofollow ugc\">#63899</a></li>\n<li>Tweak &#8211; Refine order notification email styling: adjust order summary layout and item alignment <a href=\"https://github.com/woocommerce/woocommerce/pull/63306\" rel=\"nofollow ugc\">#63306</a></li>\n<li>Performance &#8211; Added the missing shipping tables indexes to improve the performance of cart and checkout workflows for complex shipping configurations. <a href=\"https://github.com/woocommerce/woocommerce/pull/63674\" rel=\"nofollow ugc\">#63674</a></li>\n<li>Performance &#8211; Blocks: pin the number of SQL queries required to retrieve block templates from the database (2 per template type). <a href=\"https://github.com/woocommerce/woocommerce/pull/63399\" rel=\"nofollow ugc\">#63399</a></li>\n<li>Performance &#8211; Cache Store API products last modified timestamp in the object cache to avoid a database query on every request. <a href=\"https://github.com/woocommerce/woocommerce/pull/63228\" rel=\"nofollow ugc\">#63228</a></li>\n<li>Performance &#8211; Customers: guarded updates of the last activity timestamp. <a href=\"https://github.com/woocommerce/woocommerce/pull/63355\" rel=\"nofollow ugc\">#63355</a></li>\n<li>Performance &#8211; Performance: reduced the number of SQL queries required to persist a draft order during checkout (with CoGS enabled). <a href=\"https://github.com/woocommerce/woocommerce/pull/63372\" rel=\"nofollow ugc\">#63372</a></li>\n<li>Performance &#8211; Performance: reduced the number of SQL queries required to persist a draft order during checkout. <a href=\"https://github.com/woocommerce/woocommerce/pull/63258\" rel=\"nofollow ugc\">#63258</a></li>\n<li>Performance &#8211; Prime order item meta caches during HPOS order queries to eliminate N+1 queries in REST API serialization. <a href=\"https://github.com/woocommerce/woocommerce/pull/63440\" rel=\"nofollow ugc\">#63440</a></li>\n<li>Performance &#8211; Prime product caches and add targetHints to REST API v4 orders endpoint to reduce N+1 queries during serialization. <a href=\"https://github.com/woocommerce/woocommerce/pull/63654\" rel=\"nofollow ugc\">#63654</a></li>\n<li>Performance &#8211; Products: reduced the number of SQL queries required to populate cart data in StoreApi. <a href=\"https://github.com/woocommerce/woocommerce/pull/63319\" rel=\"nofollow ugc\">#63319</a></li>\n<li>Performance &#8211; Reduce SQL queries on legacy product grid blocks, Product Gallery, and Product Button by adding missing &#8220;_prime_post_caches()&#8221; calls to batch-load post data. <a href=\"https://github.com/woocommerce/woocommerce/pull/63750\" rel=\"nofollow ugc\">#63750</a></li>\n<li>Performance &#8211; Reduce the number of SQL queries on the linked products meta box and sales by product report by adding missing cache priming. <a href=\"https://github.com/woocommerce/woocommerce/pull/63737\" rel=\"nofollow ugc\">#63737</a></li>\n<li>Performance &#8211; Remove unnecessary <code>calculate_totals()</code> call from <code>DELETE /wc/store/v1/cart/coupons</code>. The result was never used since the endpoint returns an empty response body. <a href=\"https://github.com/woocommerce/woocommerce/pull/63404\" rel=\"nofollow ugc\">#63404</a></li>\n<li>Enhancement &#8211; Add optional dropdown navigation to the Customer Account block, displaying account menu links in a dropdown menu when enabled. <a href=\"https://github.com/woocommerce/woocommerce/pull/63301\" rel=\"nofollow ugc\">#63301</a></li>\n<li>Enhancement &#8211; Improve fulfillment drawer accessibility: unique ARIA IDs, fix redundant aria-labels, eliminate double screen reader announcements, and replace setTimeout-based focus management with requestAnimationFrame <a href=\"https://github.com/woocommerce/woocommerce/pull/63876\" rel=\"nofollow ugc\">#63876</a></li>\n<li>Enhancement &#8211; Integrate the payment gateway admin notification into the WooCommerce email system with full support for email styling, customizable settings, and block email editor. <a href=\"https://github.com/woocommerce/woocommerce/pull/63249\" rel=\"nofollow ugc\">#63249</a></li>\n<li>Enhancement &#8211; Make email header image/logo clickable with a link to the store homepage in classic email templates. Adds <code>woocommerce_email_header_image_url</code> filter for customization. <a href=\"https://github.com/woocommerce/woocommerce/pull/63559\" rel=\"nofollow ugc\">#63559</a></li>\n<li>Enhancement &#8211; Suppress standard transactional emails and auto-trigger POS email templates for orders paid at POS, regardless of where the order was created. <a href=\"https://github.com/woocommerce/woocommerce/pull/63322\" rel=\"nofollow ugc\">#63322</a></li>\n<li>Enhancement &#8211; Update cart, checkout, and mini-cart block item spacing to improve clarity. <a href=\"https://github.com/woocommerce/woocommerce/pull/63241\" rel=\"nofollow ugc\">#63241</a></li>\n<li>Enhancement &#8211; Use the configured email subject from WC_Email settings when sending preview emails instead of the raw post title. <a href=\"https://github.com/woocommerce/woocommerce/pull/63504\" rel=\"nofollow ugc\">#63504</a></li>\n</ul>\n<p><a href=\"https://raw.githubusercontent.com/woocommerce/woocommerce/trunk/changelog.txt\" rel=\"nofollow ugc\">Перегляньте журнал змін для всіх версій</a>.</p>\n\";s:11:\"screenshots\";s:1035:\"<ol><li><a href=\"https://ps.w.org/woocommerce/assets/screenshot-1.png?rev=3234504\"><img src=\"https://ps.w.org/woocommerce/assets/screenshot-1.png?rev=3234504\" alt=\"\"></a></li><li><a href=\"https://ps.w.org/woocommerce/assets/screenshot-2.png?rev=3234504\"><img src=\"https://ps.w.org/woocommerce/assets/screenshot-2.png?rev=3234504\" alt=\"\"></a></li><li><a href=\"https://ps.w.org/woocommerce/assets/screenshot-3.png?rev=3234504\"><img src=\"https://ps.w.org/woocommerce/assets/screenshot-3.png?rev=3234504\" alt=\"\"></a></li><li><a href=\"https://ps.w.org/woocommerce/assets/screenshot-4.png?rev=3235205\"><img src=\"https://ps.w.org/woocommerce/assets/screenshot-4.png?rev=3235205\" alt=\"\"></a></li><li><a href=\"https://ps.w.org/woocommerce/assets/screenshot-5.png?rev=3234504\"><img src=\"https://ps.w.org/woocommerce/assets/screenshot-5.png?rev=3234504\" alt=\"\"></a></li><li><a href=\"https://ps.w.org/woocommerce/assets/screenshot-6.png?rev=3234504\"><img src=\"https://ps.w.org/woocommerce/assets/screenshot-6.png?rev=3234504\" alt=\"\"></a></li></ol>\";s:7:\"reviews\";s:15402:\"<div class=\"review\">\n	<div class=\"review-head\">\n		<div class=\"reviewer-info\">\n			<div class=\"review-title-section\">\n				<h4 class=\"review-title\">Powerful and Flexible eCommerce Solution for WordPress</h4>\n				<div class=\"star-rating\">\n				<div class=\"wporg-ratings\" aria-label=\"5 з 5 зірок\" data-title-template=\"%s з 5 зірок\" data-rating=\"5\" style=\"color:#ffb900;\"><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span></div>				</div>\n			</div>\n			<p class=\"reviewer\">\n				Від <a href=\"https://profiles.wordpress.org/ammykat/\"><img alt=\'\' src=\'https://secure.gravatar.com/avatar/a3f6d86da8d61645b1ac4d0bf2ef2bfff0627667d1c3ad6200efa2d7aba103fc?s=16&#038;d=monsterid&#038;r=g\' srcset=\'https://secure.gravatar.com/avatar/a3f6d86da8d61645b1ac4d0bf2ef2bfff0627667d1c3ad6200efa2d7aba103fc?s=32&#038;d=monsterid&#038;r=g 2x\' class=\'avatar avatar-16 photo\' height=\'16\' width=\'16\' loading=\'lazy\' decoding=\'async\'/></a><a href=\"https://profiles.wordpress.org/ammykat/\" class=\"reviewer-name\">ammykat</a> о <span class=\"review-date\">15 Квітня, 2026</span>			</p>\n		</div>\n	</div>\n	<div class=\"review-body\"><!-- wp:paragraph -->\n<p>WooCommerce is a highly versatile and open-source eCommerce plugin that seamlessly integrates with WordPress, enabling users to build fully functional online stores with ease. It offers extensive customization options, supports both physical and digital products, and provides a wide range of payment and shipping integrations. With its scalable architecture and strong community support, WooCommerce is suitable for both beginners and advanced developers.</p>\n<!-- /wp:paragraph --></div>\n</div>\n<div class=\"review\">\n	<div class=\"review-head\">\n		<div class=\"reviewer-info\">\n			<div class=\"review-title-section\">\n				<h4 class=\"review-title\">Powerful but Heavy</h4>\n				<div class=\"star-rating\">\n				<div class=\"wporg-ratings\" aria-label=\"3 з 5 зірок\" data-title-template=\"%s з 5 зірок\" data-rating=\"3\" style=\"color:#ffb900;\"><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-empty\"></span><span class=\"star dashicons dashicons-star-empty\"></span></div>				</div>\n			</div>\n			<p class=\"reviewer\">\n				Від <a href=\"https://profiles.wordpress.org/franklin0/\"><img alt=\'\' src=\'https://secure.gravatar.com/avatar/dd66e320745eb739d4a59ba01057a040bbb03ca2bbb294b72200e305a469b236?s=16&#038;d=monsterid&#038;r=g\' srcset=\'https://secure.gravatar.com/avatar/dd66e320745eb739d4a59ba01057a040bbb03ca2bbb294b72200e305a469b236?s=32&#038;d=monsterid&#038;r=g 2x\' class=\'avatar avatar-16 photo\' height=\'16\' width=\'16\' loading=\'lazy\' decoding=\'async\'/></a><a href=\"https://profiles.wordpress.org/franklin0/\" class=\"reviewer-name\">franklin0</a> о <span class=\"review-date\">10 Квітня, 2026</span>			</p>\n		</div>\n	</div>\n	<div class=\"review-body\"><!-- wp:paragraph -->\n<p>Good for setting up a store. Lots of features n flexibility. But feels heavy n slow sometimes. The setup can be tricky for beginners. works well but needs patience 👍</p>\n<!-- /wp:paragraph --></div>\n</div>\n<div class=\"review\">\n	<div class=\"review-head\">\n		<div class=\"reviewer-info\">\n			<div class=\"review-title-section\">\n				<h4 class=\"review-title\">Excellent custom support</h4>\n				<div class=\"star-rating\">\n				<div class=\"wporg-ratings\" aria-label=\"5 з 5 зірок\" data-title-template=\"%s з 5 зірок\" data-rating=\"5\" style=\"color:#ffb900;\"><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span></div>				</div>\n			</div>\n			<p class=\"reviewer\">\n				Від <a href=\"https://profiles.wordpress.org/alan20spqr/\"><img alt=\'\' src=\'https://secure.gravatar.com/avatar/08a018252eaef66485a84453b11cd07b316e448193ab181d316e0a3cb09c9237?s=16&#038;d=monsterid&#038;r=g\' srcset=\'https://secure.gravatar.com/avatar/08a018252eaef66485a84453b11cd07b316e448193ab181d316e0a3cb09c9237?s=32&#038;d=monsterid&#038;r=g 2x\' class=\'avatar avatar-16 photo\' height=\'16\' width=\'16\' loading=\'lazy\' decoding=\'async\'/></a><a href=\"https://profiles.wordpress.org/alan20spqr/\" class=\"reviewer-name\">alan20spqr</a> о <span class=\"review-date\">8 Квітня, 2026</span>			</p>\n		</div>\n	</div>\n	<div class=\"review-body\"><!-- wp:paragraph -->\n<p>The WooCommerce team helped me with an issue we had on our website. Their response was fast and timely, and they helped us resolve the problem. Definitely highly recommended. We’re very grateful to them.</p>\n<!-- /wp:paragraph --></div>\n</div>\n<div class=\"review\">\n	<div class=\"review-head\">\n		<div class=\"reviewer-info\">\n			<div class=\"review-title-section\">\n				<h4 class=\"review-title\">One of the best, and free</h4>\n				<div class=\"star-rating\">\n				<div class=\"wporg-ratings\" aria-label=\"5 з 5 зірок\" data-title-template=\"%s з 5 зірок\" data-rating=\"5\" style=\"color:#ffb900;\"><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span></div>				</div>\n			</div>\n			<p class=\"reviewer\">\n				Від <a href=\"https://profiles.wordpress.org/evergf88/\"><img alt=\'\' src=\'https://secure.gravatar.com/avatar/1ae8791766608ca7482f5b86e806b64aa28b50b2b1b1b01d3a5cc9ba24e434b3?s=16&#038;d=monsterid&#038;r=g\' srcset=\'https://secure.gravatar.com/avatar/1ae8791766608ca7482f5b86e806b64aa28b50b2b1b1b01d3a5cc9ba24e434b3?s=32&#038;d=monsterid&#038;r=g 2x\' class=\'avatar avatar-16 photo\' height=\'16\' width=\'16\' loading=\'lazy\' decoding=\'async\'/></a><a href=\"https://profiles.wordpress.org/evergf88/\" class=\"reviewer-name\">evergf88</a> о <span class=\"review-date\">6 Квітня, 2026</span>			</p>\n		</div>\n	</div>\n	<div class=\"review-body\"><!-- wp:paragraph -->\n<p>WooCommerce is the critical piece of my client stores.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Free, hackeable, developer friendly. Thanks for the amazing work!</p>\n<!-- /wp:paragraph --></div>\n</div>\n<div class=\"review\">\n	<div class=\"review-head\">\n		<div class=\"reviewer-info\">\n			<div class=\"review-title-section\">\n				<h4 class=\"review-title\">Super fast and good support</h4>\n				<div class=\"star-rating\">\n				<div class=\"wporg-ratings\" aria-label=\"5 з 5 зірок\" data-title-template=\"%s з 5 зірок\" data-rating=\"5\" style=\"color:#ffb900;\"><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span></div>				</div>\n			</div>\n			<p class=\"reviewer\">\n				Від <a href=\"https://profiles.wordpress.org/bh962401/\"><img alt=\'\' src=\'https://secure.gravatar.com/avatar/31deb92085685db37cff34e0a1209e0ff541b65a3e780ade8d0525d509300c10?s=16&#038;d=monsterid&#038;r=g\' srcset=\'https://secure.gravatar.com/avatar/31deb92085685db37cff34e0a1209e0ff541b65a3e780ade8d0525d509300c10?s=32&#038;d=monsterid&#038;r=g 2x\' class=\'avatar avatar-16 photo\' height=\'16\' width=\'16\' loading=\'lazy\' decoding=\'async\'/></a><a href=\"https://profiles.wordpress.org/bh962401/\" class=\"reviewer-name\">bh962401</a> о <span class=\"review-date\">5 Квітня, 2026</span>			</p>\n		</div>\n	</div>\n	<div class=\"review-body\"><!-- wp:paragraph -->\n<p>Super fast and good support</p>\n<!-- /wp:paragraph --></div>\n</div>\n<div class=\"review\">\n	<div class=\"review-head\">\n		<div class=\"reviewer-info\">\n			<div class=\"review-title-section\">\n				<h4 class=\"review-title\">works for my store</h4>\n				<div class=\"star-rating\">\n				<div class=\"wporg-ratings\" aria-label=\"5 з 5 зірок\" data-title-template=\"%s з 5 зірок\" data-rating=\"5\" style=\"color:#ffb900;\"><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span></div>				</div>\n			</div>\n			<p class=\"reviewer\">\n				Від <a href=\"https://profiles.wordpress.org/rjspomer/\"><img alt=\'\' src=\'https://secure.gravatar.com/avatar/630a79b9384949e0ff0962a3dff230053995f8c004d13fddafb9cff5f9e952c6?s=16&#038;d=monsterid&#038;r=g\' srcset=\'https://secure.gravatar.com/avatar/630a79b9384949e0ff0962a3dff230053995f8c004d13fddafb9cff5f9e952c6?s=32&#038;d=monsterid&#038;r=g 2x\' class=\'avatar avatar-16 photo\' height=\'16\' width=\'16\' loading=\'lazy\' decoding=\'async\'/></a><a href=\"https://profiles.wordpress.org/rjspomer/\" class=\"reviewer-name\">rjspomer</a> о <span class=\"review-date\">3 Квітня, 2026</span>			</p>\n		</div>\n	</div>\n	<div class=\"review-body\"><!-- wp:paragraph -->\n<p>has been very reliable</p>\n<!-- /wp:paragraph --></div>\n</div>\n<div class=\"review\">\n	<div class=\"review-head\">\n		<div class=\"reviewer-info\">\n			<div class=\"review-title-section\">\n				<h4 class=\"review-title\">Excellent Plugin</h4>\n				<div class=\"star-rating\">\n				<div class=\"wporg-ratings\" aria-label=\"5 з 5 зірок\" data-title-template=\"%s з 5 зірок\" data-rating=\"5\" style=\"color:#ffb900;\"><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span></div>				</div>\n			</div>\n			<p class=\"reviewer\">\n				Від <a href=\"https://profiles.wordpress.org/sophiac2/\"><img alt=\'\' src=\'https://secure.gravatar.com/avatar/dff8d4f9c11298d173209cff06fa10fc13e7a985398f2aef4f25b755f521ee5a?s=16&#038;d=monsterid&#038;r=g\' srcset=\'https://secure.gravatar.com/avatar/dff8d4f9c11298d173209cff06fa10fc13e7a985398f2aef4f25b755f521ee5a?s=32&#038;d=monsterid&#038;r=g 2x\' class=\'avatar avatar-16 photo\' height=\'16\' width=\'16\' loading=\'lazy\' decoding=\'async\'/></a><a href=\"https://profiles.wordpress.org/sophiac2/\" class=\"reviewer-name\">sophiac2</a> о <span class=\"review-date\">3 Квітня, 2026</span>			</p>\n		</div>\n	</div>\n	<div class=\"review-body\"><!-- wp:paragraph -->\n<p>Very, very helpful so far.</p>\n<!-- /wp:paragraph --></div>\n</div>\n<div class=\"review\">\n	<div class=\"review-head\">\n		<div class=\"reviewer-info\">\n			<div class=\"review-title-section\">\n				<h4 class=\"review-title\">Excellent support</h4>\n				<div class=\"star-rating\">\n				<div class=\"wporg-ratings\" aria-label=\"5 з 5 зірок\" data-title-template=\"%s з 5 зірок\" data-rating=\"5\" style=\"color:#ffb900;\"><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span></div>				</div>\n			</div>\n			<p class=\"reviewer\">\n				Від <a href=\"https://profiles.wordpress.org/csdshop/\"><img alt=\'\' src=\'https://secure.gravatar.com/avatar/1bdaeab84c535abcfa93e4f3844fb7aa1edcfd9386be35784e3c0c53224c2859?s=16&#038;d=monsterid&#038;r=g\' srcset=\'https://secure.gravatar.com/avatar/1bdaeab84c535abcfa93e4f3844fb7aa1edcfd9386be35784e3c0c53224c2859?s=32&#038;d=monsterid&#038;r=g 2x\' class=\'avatar avatar-16 photo\' height=\'16\' width=\'16\' loading=\'lazy\' decoding=\'async\'/></a><a href=\"https://profiles.wordpress.org/csdshop/\" class=\"reviewer-name\">Stefano <small>(csdshop)</small></a> о <span class=\"review-date\">2 Квітня, 2026</span>			</p>\n		</div>\n	</div>\n	<div class=\"review-body\"><!-- wp:paragraph -->\n<p>We had a problem on the button \"pubblish\", after an update we resolve it.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Thank you so much!</p>\n<!-- /wp:paragraph --></div>\n</div>\n<div class=\"review\">\n	<div class=\"review-head\">\n		<div class=\"reviewer-info\">\n			<div class=\"review-title-section\">\n				<h4 class=\"review-title\">Fast and Super Helpful</h4>\n				<div class=\"star-rating\">\n				<div class=\"wporg-ratings\" aria-label=\"5 з 5 зірок\" data-title-template=\"%s з 5 зірок\" data-rating=\"5\" style=\"color:#ffb900;\"><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span></div>				</div>\n			</div>\n			<p class=\"reviewer\">\n				Від <a href=\"https://profiles.wordpress.org/christie212/\"><img alt=\'\' src=\'https://secure.gravatar.com/avatar/10000f766551bf9f6d4ac690aa771e7c718210eccd6634cb68fa535fbb87e0ba?s=16&#038;d=monsterid&#038;r=g\' srcset=\'https://secure.gravatar.com/avatar/10000f766551bf9f6d4ac690aa771e7c718210eccd6634cb68fa535fbb87e0ba?s=32&#038;d=monsterid&#038;r=g 2x\' class=\'avatar avatar-16 photo\' height=\'16\' width=\'16\' loading=\'lazy\' decoding=\'async\'/></a><a href=\"https://profiles.wordpress.org/christie212/\" class=\"reviewer-name\">christie212</a> о <span class=\"review-date\">1 Квітня, 2026</span>			</p>\n		</div>\n	</div>\n	<div class=\"review-body\"><!-- wp:paragraph -->\n<p>Had a few problems with my site but Frank Remmy and Shahzeen were super helpful and replied quickly.</p>\n<!-- /wp:paragraph --></div>\n</div>\n<div class=\"review\">\n	<div class=\"review-head\">\n		<div class=\"reviewer-info\">\n			<div class=\"review-title-section\">\n				<h4 class=\"review-title\">Good but Heavy</h4>\n				<div class=\"star-rating\">\n				<div class=\"wporg-ratings\" aria-label=\"3 з 5 зірок\" data-title-template=\"%s з 5 зірок\" data-rating=\"3\" style=\"color:#ffb900;\"><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-empty\"></span><span class=\"star dashicons dashicons-star-empty\"></span></div>				</div>\n			</div>\n			<p class=\"reviewer\">\n				Від <a href=\"https://profiles.wordpress.org/lizahamid/\"><img alt=\'\' src=\'https://secure.gravatar.com/avatar/8100921781351b6a49e75ece6e35d7f1b2644e71f67ce14a993e1bfcc963ad1f?s=16&#038;d=monsterid&#038;r=g\' srcset=\'https://secure.gravatar.com/avatar/8100921781351b6a49e75ece6e35d7f1b2644e71f67ce14a993e1bfcc963ad1f?s=32&#038;d=monsterid&#038;r=g 2x\' class=\'avatar avatar-16 photo\' height=\'16\' width=\'16\' loading=\'lazy\' decoding=\'async\'/></a><a href=\"https://profiles.wordpress.org/lizahamid/\" class=\"reviewer-name\">lizahamid</a> о <span class=\"review-date\">1 Квітня, 2026</span>			</p>\n		</div>\n	</div>\n	<div class=\"review-body\"><!-- wp:paragraph -->\n<p>Works well for online stores n has lots of features. But feels a bit heavy n setup takes time. Once done, it runs fine tho 👍</p>\n<!-- /wp:paragraph --></div>\n</div>\n\";}s:17:\"short_description\";s:296:\"Все, що вам потрібно, щоб відкрити інтернет-магазин за кілька днів і підтримувати його розвиток роками. Від вашого першого продажу до мільйонного доходу Woo з вами.\";s:13:\"download_link\";s:61:\"https://downloads.wordpress.org/plugin/woocommerce.10.7.0.zip\";s:14:\"upgrade_notice\";a:0:{}s:11:\"screenshots\";a:6:{i:1;a:2:{s:3:\"src\";s:64:\"https://ps.w.org/woocommerce/assets/screenshot-1.png?rev=3234504\";s:7:\"caption\";s:0:\"\";}i:2;a:2:{s:3:\"src\";s:64:\"https://ps.w.org/woocommerce/assets/screenshot-2.png?rev=3234504\";s:7:\"caption\";s:0:\"\";}i:3;a:2:{s:3:\"src\";s:64:\"https://ps.w.org/woocommerce/assets/screenshot-3.png?rev=3234504\";s:7:\"caption\";s:0:\"\";}i:4;a:2:{s:3:\"src\";s:64:\"https://ps.w.org/woocommerce/assets/screenshot-4.png?rev=3235205\";s:7:\"caption\";s:0:\"\";}i:5;a:2:{s:3:\"src\";s:64:\"https://ps.w.org/woocommerce/assets/screenshot-5.png?rev=3234504\";s:7:\"caption\";s:0:\"\";}i:6;a:2:{s:3:\"src\";s:64:\"https://ps.w.org/woocommerce/assets/screenshot-6.png?rev=3234504\";s:7:\"caption\";s:0:\"\";}}s:4:\"tags\";a:5:{s:9:\"ecommerce\";s:9:\"ecommerce\";s:12:\"online-store\";s:12:\"online store\";s:11:\"sell-online\";s:11:\"sell online\";s:4:\"shop\";s:4:\"shop\";s:13:\"shopping-cart\";s:13:\"shopping cart\";}s:8:\"versions\";a:623:{s:6:\"10.0.0\";s:61:\"https://downloads.wordpress.org/plugin/woocommerce.10.0.0.zip\";s:11:\"10.0.0-rc.1\";s:66:\"https://downloads.wordpress.org/plugin/woocommerce.10.0.0-rc.1.zip\";s:11:\"10.0.0-rc.2\";s:66:\"https://downloads.wordpress.org/plugin/woocommerce.10.0.0-rc.2.zip\";s:6:\"10.0.1\";s:61:\"https://downloads.wordpress.org/plugin/woocommerce.10.0.1.zip\";s:6:\"10.0.2\";s:61:\"https://downloads.wordpress.org/plugin/woocommerce.10.0.2.zip\";s:6:\"10.0.3\";s:61:\"https://downloads.wordpress.org/plugin/woocommerce.10.0.3.zip\";s:6:\"10.0.4\";s:61:\"https://downloads.wordpress.org/plugin/wooco