ypography\":{\"fontSize\":\"0.7em\"}},\"textColor\":\"foreground\"} -->\n<p class=\"has-foreground-color has-text-color\" style=\"font-size:0.7em\">\n				<strong>4.2</strong>(1,079 reviews)\n			</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:group -->\n\n<!-- wp:group {\"style\":{\"spacing\":{\"blockGap\":\"8px\",\"padding\":{\"top\":\"0px\",\"right\":\"0px\",\"bottom\":\"0px\",\"left\":\"0px\"},\"margin\":{\"top\":\"2px\",\"bottom\":\"0px\"}}},\"layout\":{\"type\":\"flex\",\"flexWrap\":\"nowrap\",\"verticalAlignment\":\"center\"}} -->\n<div class=\"wp-block-group\" style=\"margin-top:2px;margin-bottom:0px;padding-top:0px;padding-right:0px;padding-bottom:0px;padding-left:0px\"><!-- wp:paragraph {\"style\":{\"typography\":{\"fontSize\":\"1.2em\"}},\"textColor\":\"foreground\"} -->\n<p class=\"has-foreground-color has-text-color\" style=\"font-size:1.2em\">\n				<strong><sup><sub>$</sub></sup>37.49</strong>\n			</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"style\":{\"typography\":{\"fontSize\":\"0.7em\"},\"layout\":{\"selfStretch\":\"fit\",\"flexSize\":null},\"color\":{\"text\":\"#7c0a99\"}}} -->\n<p class=\"has-text-color\" style=\"color:#7c0a99;font-size:0.7em\">Save $10 <s>was $47.49</s></p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:group -->\n\n<!-- wp:group {\"layout\":{\"type\":\"constrained\",\"justifyContent\":\"left\"}} -->\n<div class=\"wp-block-group\"><!-- wp:paragraph {\"style\":{\"typography\":{\"fontSize\":\"18px\"}},\"textColor\":\"foreground\"} -->\n<p class=\"has-foreground-color has-text-color\" style=\"font-size:18px\">Designed with your well-being in mind, this chair features a contoured backrest that provides exceptional lumbar support, helping to reduce strain on your back during long hours of sitting. The adjustable height and tilt mechanisms allow you to customize the chair to your preferred sitting position, ensuring a comfortable and productive workday. Upholstered in premium fabric and available in a variety of colors, the Harmony Ergonomic Chair adds a touch of elegance to any room.</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:group -->\n\n<!-- wp:group {\"layout\":{\"type\":\"constrained\",\"justifyContent\":\"left\"}} -->\n<div class=\"wp-block-group\"><!-- wp:buttons -->\n<div class=\"wp-block-buttons\"><!-- wp:button {\"style\":{\"spacing\":{\"padding\":{\"left\":\"80px\",\"right\":\"80px\"}},\"color\":{\"text\":\"#ffffff\",\"background\":\"#000000\"}}} --><div class=\"wp-block-button\"><a class=\"wp-block-button__link has-text-color has-background wp-element-button\" style=\"color:#ffffff;background-color:#000000;padding-right:80px;padding-left:80px\">Додати у кошик</a></div><!-- /wp:button --></div>\n<!-- /wp:buttons -->\n\n<!-- wp:paragraph {\"style\":{\"typography\":{\"fontSize\":\"16px\"}}} -->\n<p style=\"font-size:16px\">SKU 6355793</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:group --></div>\n<!-- /wp:column --></div>\n<!-- /wp:columns -->\";s:14:\"disallow_after\";a:0:{}s:12:\"dependencies\";a:0:{}s:10:\"categories\";a:1:{s:16:\"_woo_woocommerce\";a:3:{s:4:\"slug\";s:16:\"_woo_woocommerce\";s:5:\"title\";s:16:\"_woo_WooCommerce\";s:11:\"description\";s:0:\"\";}}s:13:\"subcategories\";a:0:{}s:24:\"virtual_theme_categories\";a:0:{}s:4:\"tags\";a:0:{}s:12:\"pattern_meta\";a:0:{}s:10:\"source_url\";s:98:\"https://wooblockpatterns.wpcomstaging.com/2024/06/17/product-listing-with-gallery-and-description/\";s:13:\"modified_date\";s:19:\"2024-06-17 14:33:29\";s:12:\"preview_data\";a:0:{}s:23:\"pattern_design_metadata\";a:7:{s:9:\"alignment\";a:0:{}s:12:\"text_density\";a:0:{}s:13:\"media_density\";a:0:{}s:11:\"personality\";a:0:{}s:14:\"next_alignment\";a:0:{}s:17:\"next_text_density\";a:0:{}s:18:\"next_media_density\";a:0:{}}s:9:\"post_type\";s:8:\"wp_block\";s:22:\"is_included_in_big_sky\";i:0;}i:67;a:20:{s:2:\"ID\";i:188;s:7:\"site_id\";i:231214916;s:5:\"title\";s:12:\"Product Hero\";s:4:\"name\";s:12:\"product-hero\";s:11:\"description\";s:0:\"\";s:14:\"ai_description\";s:0:\"\";s:4:\"html\"