50,'amazon-mcf-review-button-2023-12-07','Leave a review','https://woocommerce.com/products/woocommerce-amazon-fulfillment/?review&utm_source=inbox_note&utm_medium=product&utm_campaign=amazon-mcf-review-button-2023-12-07','actioned','',NULL,NULL),(1901,50,'amazon-mcf-support-button-2023-12-07','Request support','https://woocommerce.com/my-account/contact-support/?utm_source=inbox_note&utm_medium=product&utm_campaign=amazon-mcf-support-button-2023-12-07','actioned','',NULL,NULL),(1902,51,'view_docs','Learn about Deposit schedules','https://woocommerce.com/document/woopayments/deposits/deposit-schedule/?utm_source=inbox_note&utm_medium=product&utm_campaign=view_docs#available-funds','unactioned','',NULL,NULL),(1903,52,'sirt-woo-2024-11-xss-admin','See available updates','http://localhost:8080/wp-admin/update-core.php?','unactioned','',NULL,NULL),(1904,52,'sirt-woo-2024-11-xss-admin','Dismiss','#','actioned','',NULL,NULL),(1905,53,'paypal-braintree-sdk-depreciation-2025-02-20-button','Upgrade now','http://localhost:8080/wp-admin/wp-admin/plugins.php','actioned','',NULL,NULL),(1906,54,'uk-vat-notice-button-2025-04-30','Learn more about this extension','https://wordpress.org/plugins/eu-vat-for-woocommerce/','actioned','',NULL,NULL),(1907,55,'paypal-braintree-sdk-depreciation-2025-05-30-button','Update now','http://localhost:8080/wp-admin/wp-admin/plugins.php','unactioned','',NULL,NULL);
